INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('fd347644-6c2d-47b4-a6d2-51a8b0f31775-ex1', 'fd347644-6c2d-47b4-a6d2-51a8b0f31775', 'pencil', 'Write your name in pencil.', '用铅笔写下你的名字。'),
  ('fd347644-6c2d-47b4-a6d2-51a8b0f31775-ex2', 'fd347644-6c2d-47b4-a6d2-51a8b0f31775', 'pencil', 'The meeting was penciled in pending confirmation of the agenda.', '会议暂定，待议程确认后落实。'),
  ('c363b7e1-f54b-419d-a460-dc8b8f886672-ex1', 'c363b7e1-f54b-419d-a460-dc8b8f886672', 'detention', 'He got detention after school.', '他放学后被留校了。'),
  ('c363b7e1-f54b-419d-a460-dc8b8f886672-ex2', 'c363b7e1-f54b-419d-a460-dc8b8f886672', 'detention', 'The commission documented serious abuses in the detention facilities.', '委员会记录了拘留设施中的严重虐待行为。'),
  ('56309733-4d7e-478d-9494-c527cb208c1e-ex1', '56309733-4d7e-478d-9494-c527cb208c1e', 'indict', 'The grand jury voted to indict him.', '大陪审团投票决定起诉他。'),
  ('56309733-4d7e-478d-9494-c527cb208c1e-ex2', '56309733-4d7e-478d-9494-c527cb208c1e', 'indict', 'Prosecutors indicted five former executives for orchestrating the fraud.', '检察官起诉了五名策划这起欺诈的前高管。'),
  ('d1ba62d8-93a2-4fa6-9689-67ebc5655a2d-ex1', 'd1ba62d8-93a2-4fa6-9689-67ebc5655a2d', 'frontier', 'They crossed the frontier at dawn.', '他们在黎明时分越过了边境。'),
  ('d1ba62d8-93a2-4fa6-9689-67ebc5655a2d-ex2', 'd1ba62d8-93a2-4fa6-9689-67ebc5655a2d', 'frontier', 'The case pushes the frontier of liability for autonomous systems.', '该案推进了自主系统责任认定的前沿。'),
  ('734fa4c0-6676-4978-a504-5387403b3761-ex1', '734fa4c0-6676-4978-a504-5387403b3761', 'innocence', 'He maintained his innocence.', '他坚称自己无罪。'),
  ('734fa4c0-6676-4978-a504-5387403b3761-ex2', '734fa4c0-6676-4978-a504-5387403b3761', 'innocence', 'The presumption of innocence persists until guilt is proven beyond doubt.', '在排除合理怀疑地证明有罪之前，无罪推定始终成立。'),
  ('b41552cf-d742-4c32-8961-dd3556ea4c10-ex1', 'b41552cf-d742-4c32-8961-dd3556ea4c10', 'spray', 'She used bug spray on the plants.', '她给植物喷了杀虫剂。'),
  ('b41552cf-d742-4c32-8961-dd3556ea4c10-ex2', 'b41552cf-d742-4c32-8961-dd3556ea4c10', 'spray', 'The pesticide spray contaminated the watershed serving downstream communities.', '农药喷洒污染了为下游社区供水的流域。'),
  ('ace8f4f9-a616-418f-b568-99c585c06b34-ex1', 'ace8f4f9-a616-418f-b568-99c585c06b34', 'judiciary', 'The judiciary is independent.', '司法部门是独立的。'),
  ('ace8f4f9-a616-418f-b568-99c585c06b34-ex2', 'ace8f4f9-a616-418f-b568-99c585c06b34', 'judiciary', 'An independent judiciary is the indispensable guarantor of constitutional rights.', '独立的司法机构是宪法权利不可或缺的保障。'),
  ('0fe923da-8e59-43c1-9573-1b1420c2b1a3-ex1', '0fe923da-8e59-43c1-9573-1b1420c2b1a3', 'liable', 'You are liable for the damage.', '你要对损失负责。'),
  ('0fe923da-8e59-43c1-9573-1b1420c2b1a3-ex2', '0fe923da-8e59-43c1-9573-1b1420c2b1a3', 'liable', 'The manufacturer is liable for defects present at the time of distribution.', '制造商对出厂时即存在的缺陷承担责任。'),
  ('2e2b5eec-fada-4577-b503-2c4e535cd77f-ex1', '2e2b5eec-fada-4577-b503-2c4e535cd77f', 'disclose', 'Please disclose any allergies.', '请说明任何过敏情况。'),
  ('2e2b5eec-fada-4577-b503-2c4e535cd77f-ex2', '2e2b5eec-fada-4577-b503-2c4e535cd77f', 'disclose', 'Directors must disclose any interest that could compromise their impartiality.', '董事必须披露任何可能影响其公正性的利益。'),
  ('315e21ad-f3d3-45df-a34d-352b4d179d40-ex1', '315e21ad-f3d3-45df-a34d-352b4d179d40', 'litigate', 'They chose to litigate the dispute.', '他们选择通过诉讼解决争端。'),
  ('315e21ad-f3d3-45df-a34d-352b4d179d40-ex2', '315e21ad-f3d3-45df-a34d-352b4d179d40', 'litigate', 'The parties litigated the estate for nearly a decade across three jurisdictions.', '各方就这笔遗产横跨三个司法管辖区诉讼了近十年。'),
  ('4c80e32e-fe85-42e4-9ec0-3035f837eddc-ex1', '4c80e32e-fe85-42e4-9ec0-3035f837eddc', 'custody', 'She has custody of the children.', '她拥有孩子的监护权。'),
  ('4c80e32e-fe85-42e4-9ec0-3035f837eddc-ex2', '4c80e32e-fe85-42e4-9ec0-3035f837eddc', 'custody', 'Evidence in police custody must be preserved under documented chain of custody.', '警方保管的证据必须按有记录的保管链妥善保存。'),
  ('0e75ab96-d48c-4162-bfd4-f977d1fea927-ex1', '0e75ab96-d48c-4162-bfd4-f977d1fea927', 'mediate', 'A teacher mediated the dispute.', '一位老师调解了纠纷。'),
  ('0e75ab96-d48c-4162-bfd4-f977d1fea927-ex2', '0e75ab96-d48c-4162-bfd4-f977d1fea927', 'mediate', 'The envoy was authorized to mediate between the parties to the conflict.', '这位特使获授权在冲突各方之间进行调解。'),
  ('4936f361-425f-49fa-8948-f8ef36165e42-ex1', '4936f361-425f-49fa-8948-f8ef36165e42', 'banker', 'Her father is a banker.', '她父亲是一名银行家。'),
  ('4936f361-425f-49fa-8948-f8ef36165e42-ex2', '4936f361-425f-49fa-8948-f8ef36165e42', 'banker', 'The central banker''s testimony shaped the entire policy debate.', '这位央行官员的证词左右了整场政策辩论。'),
  ('54d1e09e-3f1c-4286-8d11-d90a3188446a-ex1', '54d1e09e-3f1c-4286-8d11-d90a3188446a', 'beast', 'The lion is a powerful beast.', '狮子是一种强壮的野兽。'),
  ('54d1e09e-3f1c-4286-8d11-d90a3188446a-ex2', '54d1e09e-3f1c-4286-8d11-d90a3188446a', 'beast', 'Bureaucratic inertia is a beast no single reform can readily tame.', '官僚惰性是任何单一改革都难以轻易驯服的猛兽。'),
  ('f8eae1b2-c23a-475e-a13a-64a54bdb3e41-ex1', 'f8eae1b2-c23a-475e-a13a-64a54bdb3e41', 'oath', 'He took an oath of office.', '他宣誓就职。'),
  ('f8eae1b2-c23a-475e-a13a-64a54bdb3e41-ex2', 'f8eae1b2-c23a-475e-a13a-64a54bdb3e41', 'oath', 'Witnesses must give evidence under oath before the tribunal.', '证人必须在法庭上宣誓后作证。'),
  ('09e271e6-8f53-4957-a05d-620a2d2ffb26-ex1', '09e271e6-8f53-4957-a05d-620a2d2ffb26', 'oblige', 'I would be happy to oblige.', '我很乐意效劳。'),
  ('09e271e6-8f53-4957-a05d-620a2d2ffb26-ex2', '09e271e6-8f53-4957-a05d-620a2d2ffb26', 'oblige', 'The statute obliges employers to provide a safe working environment.', '该法规要求雇主提供安全的工作环境。'),
  ('d5295680-8248-447c-894d-72ff3eee2d2d-ex1', 'd5295680-8248-447c-894d-72ff3eee2d2d', 'interfere', 'Don''t interfere in their business.', '别干涉他们的事。'),
  ('d5295680-8248-447c-894d-72ff3eee2d2d-ex2', 'd5295680-8248-447c-894d-72ff3eee2d2d', 'interfere', 'The convention forbids states from interfering in each other''s internal affairs.', '该公约禁止各国干涉彼此的内政。'),
  ('3ead362b-b7e5-4117-96dd-991e6f37227e-ex1', '3ead362b-b7e5-4117-96dd-991e6f37227e', 'offence', 'Speeding is a minor offence.', '超速是轻微的违法行为。'),
  ('3ead362b-b7e5-4117-96dd-991e6f37227e-ex2', '3ead362b-b7e5-4117-96dd-991e6f37227e', 'offence', 'The conduct constitutes a strict-liability offence regardless of intent.', '无论是否存在故意，该行为均构成严格责任罪。'),
  ('7ed65641-6309-46b5-8ea2-4dcd0a609733-ex1', '7ed65641-6309-46b5-8ea2-4dcd0a609733', 'oak', 'The table is made of oak.', '这张桌子是橡木做的。'),
  ('7ed65641-6309-46b5-8ea2-4dcd0a609733-ex2', '7ed65641-6309-46b5-8ea2-4dcd0a609733', 'oak', 'The ordinance prohibits felling a mature oak without municipal authorization.', '该条例禁止未经市政许可砍伐成年橡树。'),
  ('65c0b85e-ecef-4521-95de-50f64587b178-ex1', '65c0b85e-ecef-4521-95de-50f64587b178', 'rights', 'Know your rights as a tenant.', '了解你作为租户的权利。'),
  ('65c0b85e-ecef-4521-95de-50f64587b178-ex2', '65c0b85e-ecef-4521-95de-50f64587b178', 'rights', 'The charter affirms rights that no emergency measure may lawfully suspend.', '宪章确认的权利不得因任何紧急措施而合法中止。'),
  ('4fb5d792-3261-49bf-b862-1ed53bf5d43f-ex1', '4fb5d792-3261-49bf-b862-1ed53bf5d43f', 'eighth', 'Today is the eighth of June.', '今天是六月八日。'),
  ('4fb5d792-3261-49bf-b862-1ed53bf5d43f-ex2', '4fb5d792-3261-49bf-b862-1ed53bf5d43f', 'eighth', 'The eighth tranche of funding is conditioned on verified milestones.', '第八笔资金的拨付以经核实的里程碑为条件。'),
  ('765458c2-2482-4083-bf1e-26d9a17be152-ex1', '765458c2-2482-4083-bf1e-26d9a17be152', 'sentencing', 'The sentencing is scheduled for Friday.', '量刑定于周五进行。'),
  ('765458c2-2482-4083-bf1e-26d9a17be152-ex2', '765458c2-2482-4083-bf1e-26d9a17be152', 'sentencing', 'The commission documented persistent disparities in sentencing correlated with race.', '委员会记录了与种族相关的、长期存在的量刑差异。'),
  ('22e58082-ca2b-469a-8080-ba0c3ba0daf2-ex1', '22e58082-ca2b-469a-8080-ba0c3ba0daf2', 'theft', 'He reported the theft to the police.', '他向警方报告了盗窃案。'),
  ('22e58082-ca2b-469a-8080-ba0c3ba0daf2-ex2', '22e58082-ca2b-469a-8080-ba0c3ba0daf2', 'theft', 'The statute criminalizes identity theft committed through digital impersonation.', '该法规将通过数字冒充实施的身份盗窃定为犯罪。'),
  ('b427c033-4af6-4a0b-a245-1e0693b836e1-ex1', 'b427c033-4af6-4a0b-a245-1e0693b836e1', 'notebook', 'She wrote it in her notebook.', '她记在了笔记本上。'),
  ('b427c033-4af6-4a0b-a245-1e0693b836e1-ex2', 'b427c033-4af6-4a0b-a245-1e0693b836e1', 'notebook', 'The seized notebook contained records contradicting the public statements.', '被扣押的笔记本中存有与公开声明相矛盾的记录。'),
  ('605a175d-6d7e-4192-9ab0-fa1a457d8e27-ex1', '605a175d-6d7e-4192-9ab0-fa1a457d8e27', 'outline', 'Write an outline before the essay.', '写作文前先列提纲。'),
  ('605a175d-6d7e-4192-9ab0-fa1a457d8e27-ex2', '605a175d-6d7e-4192-9ab0-fa1a457d8e27', 'outline', 'The white paper outlines the principles governing the forthcoming legislation.', '白皮书概述了即将出台立法所遵循的原则。'),
  ('b8323eb0-ee6c-4245-a75f-82b7fcde1ad8-ex1', 'b8323eb0-ee6c-4245-a75f-82b7fcde1ad8', 'an', 'I ate an apple for lunch.', '我午饭吃了一个苹果。'),
  ('b8323eb0-ee6c-4245-a75f-82b7fcde1ad8-ex2', 'b8323eb0-ee6c-4245-a75f-82b7fcde1ad8', 'an', 'An institution capable of withstanding such scrutiny earns enduring public trust.', '一个能经受住这种审查的机构会赢得持久的公众信任。'),
  ('7f6c6089-c689-4cd5-ac54-162947996fec-ex1', '7f6c6089-c689-4cd5-ac54-162947996fec', 'Dr', 'Dr Smith will see you now.', '史密斯医生现在可以见你了。'),
  ('7f6c6089-c689-4cd5-ac54-162947996fec-ex2', '7f6c6089-c689-4cd5-ac54-162947996fec', 'Dr', 'Dr Alvarez testified about the long-term effects of the exposure.', '阿尔瓦雷斯博士就这种接触的长期影响出庭作证。'),
  ('37baf57e-c123-4e74-add1-949b7da3de95-ex1', '37baf57e-c123-4e74-add1-949b7da3de95', 'attendance', 'Attendance is mandatory.', '出席是强制性的。'),
  ('37baf57e-c123-4e74-add1-949b7da3de95-ex2', '37baf57e-c123-4e74-add1-949b7da3de95', 'attendance', 'The school breakfast program measurably improved attendance and attainment.', '学校早餐计划显著改善了出勤率和学业成绩。'),
  ('778b29d6-5377-46bd-b244-9a83f0adb55c-ex1', '778b29d6-5377-46bd-b244-9a83f0adb55c', 'theirs', 'That house is theirs.', '那栋房子是他们的。'),
  ('778b29d6-5377-46bd-b244-9a83f0adb55c-ex2', '778b29d6-5377-46bd-b244-9a83f0adb55c', 'theirs', 'The responsibility for these failures is theirs, not their successors''.', '这些失误的责任在于他们，而非其继任者。'),
  ('70924752-2bac-4fee-aab4-28c656c58dff-ex1', '70924752-2bac-4fee-aab4-28c656c58dff', 'yourselves', 'Help yourselves to the snacks.', '请随意享用零食。'),
  ('70924752-2bac-4fee-aab4-28c656c58dff-ex2', '70924752-2bac-4fee-aab4-28c656c58dff', 'yourselves', 'You must satisfy yourselves that the safeguards operate as designed.', '你们必须确信这些保障措施按设计运作。'),
  ('f67cd25f-2101-4686-951f-48df07b52860-ex1', 'f67cd25f-2101-4686-951f-48df07b52860', 'api', 'The app connects through an API.', '这个应用通过API连接。'),
  ('f67cd25f-2101-4686-951f-48df07b52860-ex2', 'f67cd25f-2101-4686-951f-48df07b52860', 'api', 'The breach exploited an API that lacked proper authentication.', '这次入侵利用了一个缺乏适当身份验证的接口。'),
  ('feca0a1f-a076-4a81-9abb-8cd943e66284-ex1', 'feca0a1f-a076-4a81-9abb-8cd943e66284', 'speculation', 'The news sparked speculation.', '这则消息引发了猜测。'),
  ('feca0a1f-a076-4a81-9abb-8cd943e66284-ex2', 'feca0a1f-a076-4a81-9abb-8cd943e66284', 'speculation', 'Speculation drove valuations far beyond any defensible fundamentals.', '投机将估值推升至远超任何站得住脚的基本面。'),
  ('ce92f19f-8fac-4b47-adc9-1fd14bc63ad5-ex1', 'ce92f19f-8fac-4b47-adc9-1fd14bc63ad5', 'payload', 'The rocket carried a heavy payload.', '火箭携带了沉重的载荷。'),
  ('ce92f19f-8fac-4b47-adc9-1fd14bc63ad5-ex2', 'ce92f19f-8fac-4b47-adc9-1fd14bc63ad5', 'payload', 'The malicious payload was concealed within an otherwise legitimate request.', '恶意载荷被隐藏在一个看似正常的请求之中。'),
  ('fda2fbd2-d2b6-43be-b21a-a68e31fd8b05-ex1', 'fda2fbd2-d2b6-43be-b21a-a68e31fd8b05', 'uncover', 'The dig uncovered ancient bones.', '这次发掘出土了古代的骨骼。'),
  ('fda2fbd2-d2b6-43be-b21a-a68e31fd8b05-ex2', 'fda2fbd2-d2b6-43be-b21a-a68e31fd8b05', 'uncover', 'The audit uncovered liabilities concealed through off-balance-sheet entities.', '审计揭露了通过表外实体隐藏的负债。'),
  ('00270ce4-8823-4488-a0ac-ea6a75fdb586-ex1', '00270ce4-8823-4488-a0ac-ea6a75fdb586', 'behalf', 'I am speaking on behalf of the team.', '我代表团队发言。'),
  ('00270ce4-8823-4488-a0ac-ea6a75fdb586-ex2', '00270ce4-8823-4488-a0ac-ea6a75fdb586', 'behalf', 'Counsel was authorized to act on behalf of all the affected claimants.', '律师获授权代表所有受影响的索赔人行事。'),
  ('01b8a317-370e-43ae-88f0-c84b58d57829-ex1', '01b8a317-370e-43ae-88f0-c84b58d57829', 'authentication', 'The site requires two-factor authentication.', '该网站需要双重身份验证。'),
  ('01b8a317-370e-43ae-88f0-c84b58d57829-ex2', '01b8a317-370e-43ae-88f0-c84b58d57829', 'authentication', 'The breach succeeded because the endpoint lacked proper authentication.', '这次入侵之所以得手，是因为该接口缺乏适当的身份验证。'),
  ('47856694-63f3-4669-9cb2-5444a9c0c39a-ex1', '47856694-63f3-4669-9cb2-5444a9c0c39a', 'authorization', 'You need authorization to enter.', '进入需要授权。'),
  ('47856694-63f3-4669-9cb2-5444a9c0c39a-ex2', '47856694-63f3-4669-9cb2-5444a9c0c39a', 'authorization', 'The disbursement contravened the appropriations act for want of authorization.', '这笔支出因缺乏授权而违反了拨款法。'),
  ('efd94d15-3527-45e9-a4c5-7bd3c10eb95e-ex1', 'efd94d15-3527-45e9-a4c5-7bd3c10eb95e', 'innovative', 'The school uses innovative methods.', '这所学校采用创新的方法。'),
  ('efd94d15-3527-45e9-a4c5-7bd3c10eb95e-ex2', 'efd94d15-3527-45e9-a4c5-7bd3c10eb95e', 'innovative', 'The bridge''s innovative design earned international recognition for ingenuity.', '这座桥的创新设计因其巧思而获得国际赞誉。'),
  ('85d72b04-90bf-497f-beb1-5418632ff718-ex1', '85d72b04-90bf-497f-beb1-5418632ff718', 'shark', 'We saw a shark from the boat.', '我们从船上看到了一条鲨鱼。'),
  ('85d72b04-90bf-497f-beb1-5418632ff718-ex2', '85d72b04-90bf-497f-beb1-5418632ff718', 'shark', 'Predatory lenders circled the distressed firm like sharks scenting blood.', '掠夺性放贷者像嗅到血腥的鲨鱼一样围住了这家陷入困境的公司。'),
  ('d5478063-7c44-4746-a0ce-c706c55ee1fc-ex1', 'd5478063-7c44-4746-a0ce-c706c55ee1fc', 'deployment', 'The deployment went smoothly.', '这次部署很顺利。'),
  ('d5478063-7c44-4746-a0ce-c706c55ee1fc-ex2', 'd5478063-7c44-4746-a0ce-c706c55ee1fc', 'deployment', 'The failed deployment triggered an automatic rollback to the prior version.', '部署失败触发了向先前版本的自动回滚。'),
  ('e5293730-81f4-4867-b54b-59b807fdea63-ex1', 'e5293730-81f4-4867-b54b-59b807fdea63', 'docker', 'We package the app with Docker.', '我们用Docker打包应用。'),
  ('e5293730-81f4-4867-b54b-59b807fdea63-ex2', 'e5293730-81f4-4867-b54b-59b807fdea63', 'docker', 'Each service runs in an isolated Docker container for portability.', '为了可移植性，每个服务都在独立的Docker容器中运行。'),
  ('2f31f13c-0e84-4712-88a6-1e121102be50-ex1', '2f31f13c-0e84-4712-88a6-1e121102be50', 'mill', 'The old mill ground wheat.', '这座老磨坊磨小麦。'),
  ('2f31f13c-0e84-4712-88a6-1e121102be50-ex2', '2f31f13c-0e84-4712-88a6-1e121102be50', 'mill', 'The factory closure devastated a town built around its single mill.', '工厂倒闭重创了这座围绕单一工厂兴起的城镇。'),
  ('ad9a8f74-10c0-405d-8dde-6c9617f203e6-ex1', 'ad9a8f74-10c0-405d-8dde-6c9617f203e6', 'kubernetes', 'They deploy services on Kubernetes.', '他们在Kubernetes上部署服务。'),
