  ('3e38ecd8-9725-4981-97e5-c4aca283f405-ex2', '3e38ecd8-9725-4981-97e5-c4aca283f405', 'planner', 'The planner''s approval was quashed for failure to assess cumulative impacts.', '规划部门的批准因未评估累积影响而被撤销。'),
  ('cfc72f7f-ccc6-4958-9639-d0850478e428-ex1', 'cfc72f7f-ccc6-4958-9639-d0850478e428', 'appetite', 'The walk gave me an appetite.', '散步让我胃口大开。'),
  ('cfc72f7f-ccc6-4958-9639-d0850478e428-ex2', 'cfc72f7f-ccc6-4958-9639-d0850478e428', 'appetite', 'Investor appetite for the bonds evaporated once the guarantee was questioned.', '担保一受质疑，投资者对这些债券的兴趣便烟消云散。'),
  ('2406ef03-cbef-4df4-9a8a-cd87deb887eb-ex1', '2406ef03-cbef-4df4-9a8a-cd87deb887eb', 'depressed', 'He felt depressed after the loss.', '失利后他情绪低落。'),
  ('2406ef03-cbef-4df4-9a8a-cd87deb887eb-ex2', '2406ef03-cbef-4df4-9a8a-cd87deb887eb', 'depressed', 'Asset prices remained depressed long after the formal recovery began.', '在正式复苏开始后很久，资产价格仍然低迷。'),
  ('2b9c31a5-7440-4ae8-9463-486efec48851-ex1', '2b9c31a5-7440-4ae8-9463-486efec48851', 'applaud', 'The audience applauded loudly.', '观众热烈鼓掌。'),
  ('2b9c31a5-7440-4ae8-9463-486efec48851-ex2', '2b9c31a5-7440-4ae8-9463-486efec48851', 'applaud', 'Observers applauded the ruling as a victory for procedural fairness.', '观察人士称赞该裁决是程序公正的胜利。'),
  ('628c80e9-4465-447c-b15d-69b90c97317e-ex1', '628c80e9-4465-447c-b15d-69b90c97317e', 'applicable', 'The rule is applicable to everyone.', '这条规则适用于所有人。'),
  ('628c80e9-4465-447c-b15d-69b90c97317e-ex2', '628c80e9-4465-447c-b15d-69b90c97317e', 'applicable', 'The claim was time-barred under the applicable statute of limitations.', '根据可适用的诉讼时效法规，该索赔已经超期。'),
  ('b67d39f9-7a41-410c-a9c1-4477ac164491-ex1', 'b67d39f9-7a41-410c-a9c1-4477ac164491', 'chunk', 'He cut a chunk of cheese.', '他切了一大块奶酪。'),
  ('b67d39f9-7a41-410c-a9c1-4477ac164491-ex2', 'b67d39f9-7a41-410c-a9c1-4477ac164491', 'chunk', 'A substantial chunk of the proceeds remains frozen pending forfeiture.', '相当大一部分收益在没收程序结束前仍被冻结。'),
  ('6b53903a-6282-480c-80d5-1884bc9ebf5d-ex1', '6b53903a-6282-480c-80d5-1884bc9ebf5d', 'appropriately', 'Dress appropriately for the weather.', '根据天气穿合适的衣服。'),
  ('6b53903a-6282-480c-80d5-1884bc9ebf5d-ex2', '6b53903a-6282-480c-80d5-1884bc9ebf5d', 'appropriately', 'Sanctions must be calibrated appropriately to the gravity of the violation.', '处罚必须与违规的严重程度恰当匹配。'),
  ('dbb532cb-4dc1-4200-99aa-6e9f5d6dad43-ex1', 'dbb532cb-4dc1-4200-99aa-6e9f5d6dad43', 'closest', 'The closest station is two blocks away.', '最近的车站在两个街区外。'),
  ('dbb532cb-4dc1-4200-99aa-6e9f5d6dad43-ex2', 'dbb532cb-4dc1-4200-99aa-6e9f5d6dad43', 'closest', 'The precedent closest on its facts supports the narrower construction.', '事实上最接近的先例支持较窄的解释。'),
  ('8b92df30-bb7a-44e8-beed-562577d4bf54-ex1', '8b92df30-bb7a-44e8-beed-562577d4bf54', 'april', 'My birthday is in April.', '我的生日在四月。'),
  ('8b92df30-bb7a-44e8-beed-562577d4bf54-ex2', '8b92df30-bb7a-44e8-beed-562577d4bf54', 'april', 'The provisions take effect from the first day of April next fiscal year.', '这些条款自下一财年四月一日起生效。'),
  ('c7452487-6e0b-4d95-98ae-7f5788797a03-ex1', 'c7452487-6e0b-4d95-98ae-7f5788797a03', 'discount', 'Students get a ten percent discount.', '学生可享受九折优惠。'),
  ('c7452487-6e0b-4d95-98ae-7f5788797a03-ex2', 'c7452487-6e0b-4d95-98ae-7f5788797a03', 'discount', 'The tribunal declined to discount testimony merely for minor inconsistencies.', '法庭拒绝仅因细微出入而贬低证词的价值。'),
  ('16ec98ee-3cc7-4aa5-ba5a-15bc3e3fa0ed-ex1', '16ec98ee-3cc7-4aa5-ba5a-15bc3e3fa0ed', 'arbitrary', 'The choice of color was arbitrary.', '颜色的选择是随意的。'),
  ('16ec98ee-3cc7-4aa5-ba5a-15bc3e3fa0ed-ex2', '16ec98ee-3cc7-4aa5-ba5a-15bc3e3fa0ed', 'arbitrary', 'The court struck down the measure as arbitrary and devoid of reasoned basis.', '法院以恣意且缺乏说理依据为由废止了该措施。'),
  ('21f24708-445c-4b99-bc9e-ac0bbe5e007b-ex1', '21f24708-445c-4b99-bc9e-ac0bbe5e007b', 'ladder', 'He climbed the ladder to the roof.', '他爬梯子上了屋顶。'),
  ('21f24708-445c-4b99-bc9e-ac0bbe5e007b-ex2', '21f24708-445c-4b99-bc9e-ac0bbe5e007b', 'ladder', 'Stagnant wages have broken the lower rungs of the economic ladder.', '工资停滞已使经济阶梯的底层阶级失去上升通道。'),
  ('364d2f59-ccf4-4a1f-a9c5-16da7b8bd0e5-ex1', '364d2f59-ccf4-4a1f-a9c5-16da7b8bd0e5', 'architectural', 'The city is famous for its architectural beauty.', '这座城市以建筑之美闻名。'),
  ('364d2f59-ccf4-4a1f-a9c5-16da7b8bd0e5-ex2', '364d2f59-ccf4-4a1f-a9c5-16da7b8bd0e5', 'architectural', 'The architectural plans required certification against the revised seismic code.', '建筑图纸须按修订后的抗震规范进行认证。'),
  ('1e13b1f0-f8c6-4255-86f0-2cc35669075f-ex1', '1e13b1f0-f8c6-4255-86f0-2cc35669075f', 'archive', 'The photos are stored in the archive.', '照片存放在档案室里。'),
  ('1e13b1f0-f8c6-4255-86f0-2cc35669075f-ex2', '1e13b1f0-f8c6-4255-86f0-2cc35669075f', 'archive', 'The declassified archive transformed scholarly understanding of the era.', '解密档案彻底改变了学界对那个时代的认识。'),
  ('f1b9fe06-f409-4309-b89b-db960f723900-ex1', 'f1b9fe06-f409-4309-b89b-db960f723900', 'jungle', 'Many animals live in the jungle.', '许多动物生活在丛林里。'),
  ('f1b9fe06-f409-4309-b89b-db960f723900-ex2', 'f1b9fe06-f409-4309-b89b-db960f723900', 'jungle', 'Claimants navigate a procedural jungle of overlapping forums and deadlines.', '索赔人要在管辖重叠、期限交错的程序丛林中摸索前行。'),
  ('a29d1eb3-f402-4b80-807c-a6f65f2ac0b4-ex1', 'a29d1eb3-f402-4b80-807c-a6f65f2ac0b4', 'migration', 'We watched the bird migration in autumn.', '秋天我们观看了候鸟迁徙。'),
  ('a29d1eb3-f402-4b80-807c-a6f65f2ac0b4-ex2', 'a29d1eb3-f402-4b80-807c-a6f65f2ac0b4', 'migration', 'The summit failed to address the structural drivers of migration.', '峰会未能解决移民问题的结构性动因。'),
  ('a2ae7e76-9444-46e3-85d7-06419928f847-ex1', 'a2ae7e76-9444-46e3-85d7-06419928f847', 'arms', 'She held the baby in her arms.', '她把宝宝抱在怀里。'),
  ('a2ae7e76-9444-46e3-85d7-06419928f847-ex2', 'a2ae7e76-9444-46e3-85d7-06419928f847', 'arms', 'The embargo prohibits arms transfers to parties to the conflict.', '禁运禁止向冲突各方转让武器。'),
  ('a0231821-ec8e-4758-8de0-ae775cdbe32e-ex1', 'a0231821-ec8e-4758-8de0-ae775cdbe32e', 'breathing', 'Deep breathing helps you relax.', '深呼吸有助于放松。'),
  ('a0231821-ec8e-4758-8de0-ae775cdbe32e-ex2', 'a0231821-ec8e-4758-8de0-ae775cdbe32e', 'breathing', 'The moratorium gave the restructuring vital breathing room.', '暂停令为重组争取到了至关重要的喘息空间。'),
  ('ce18f3ad-fc6f-48cc-8eda-b19ad29438eb-ex1', 'ce18f3ad-fc6f-48cc-8eda-b19ad29438eb', 'artwork', 'Her artwork hangs in the school hall.', '她的画作挂在学校大厅里。'),
  ('ce18f3ad-fc6f-48cc-8eda-b19ad29438eb-ex2', 'ce18f3ad-fc6f-48cc-8eda-b19ad29438eb', 'artwork', 'The artwork was repatriated after decades of provenance litigation.', '经过数十年的来源诉讼，这件艺术品终被归还。'),
  ('5767bfce-0102-4cb4-be6f-343a602aad22-ex1', '5767bfce-0102-4cb4-be6f-343a602aad22', 'invade', 'Weeds invaded the garden.', '杂草侵占了花园。'),
  ('5767bfce-0102-4cb4-be6f-343a602aad22-ex2', '5767bfce-0102-4cb4-be6f-343a602aad22', 'invade', 'The surveillance was held to invade constitutionally protected privacy.', '这种监控被裁定侵犯了宪法保护的隐私。'),
  ('91619350-377b-4e3a-b08d-5d0eb075bebd-ex1', '91619350-377b-4e3a-b08d-5d0eb075bebd', 'ashamed', 'He was ashamed of his mistake.', '他为自己的错误感到羞愧。'),
  ('91619350-377b-4e3a-b08d-5d0eb075bebd-ex2', '91619350-377b-4e3a-b08d-5d0eb075bebd', 'ashamed', 'The chairman professed himself ashamed of failures under his stewardship.', '董事长表示为其任内的失误感到羞愧。'),
  ('bdfab55f-52f6-4e78-afe9-31ce1062b1ef-ex1', 'bdfab55f-52f6-4e78-afe9-31ce1062b1ef', 'hurricane', 'The hurricane damaged many houses.', '飓风毁坏了许多房屋。'),
  ('bdfab55f-52f6-4e78-afe9-31ce1062b1ef-ex2', 'bdfab55f-52f6-4e78-afe9-31ce1062b1ef', 'hurricane', 'Hurricane losses tested the adequacy of the catastrophe reinsurance pool.', '飓风损失考验了巨灾再保险资金池的充足性。'),
  ('d1e927f5-e984-4b18-8724-445d5b06baee-ex1', 'd1e927f5-e984-4b18-8724-445d5b06baee', 'aspiration', 'Her aspiration is to become a doctor.', '她的志向是成为一名医生。'),
  ('d1e927f5-e984-4b18-8724-445d5b06baee-ex2', 'd1e927f5-e984-4b18-8724-445d5b06baee', 'aspiration', 'The pledges remain aspirations absent binding implementing measures.', '如无约束性落实措施，这些承诺仍只是愿景。'),
  ('2ee48f0e-f1d7-4890-a2f3-f285d0dc270f-ex1', '2ee48f0e-f1d7-4890-a2f3-f285d0dc270f', 'aspire', 'He aspires to play in the national team.', '他立志进入国家队。'),
  ('2ee48f0e-f1d7-4890-a2f3-f285d0dc270f-ex2', '2ee48f0e-f1d7-4890-a2f3-f285d0dc270f', 'aspire', 'Institutions that aspire to credibility must submit to independent audit.', '追求公信力的机构必须接受独立审计。'),
  ('cabc398a-3cd8-4fd3-b8d8-fad9d2abeed1-ex1', 'cabc398a-3cd8-4fd3-b8d8-fad9d2abeed1', 'retailer', 'The retailer offers free delivery.', '这家零售商提供免费送货。'),
  ('cabc398a-3cd8-4fd3-b8d8-fad9d2abeed1-ex2', 'cabc398a-3cd8-4fd3-b8d8-fad9d2abeed1', 'retailer', 'Retailers bear due diligence duties across their supply chains.', '零售商对其供应链负有尽职调查义务。'),
  ('7a2c0227-a6a2-4150-9404-6551598b492f-ex1', '7a2c0227-a6a2-4150-9404-6551598b492f', 'classify', 'Classify the books by subject.', '按学科给图书分类。'),
  ('7a2c0227-a6a2-4150-9404-6551598b492f-ex2', '7a2c0227-a6a2-4150-9404-6551598b492f', 'classify', 'The agency moved to classify the documents on national security grounds.', '该机构以国家安全为由将这些文件列为机密。'),
  ('e32895d6-daf1-479a-b571-55f690245a5c-ex1', 'e32895d6-daf1-479a-b571-55f690245a5c', 'assassination', 'The assassination shocked the whole nation.', '这起暗杀事件震惊了全国。'),
  ('e32895d6-daf1-479a-b571-55f690245a5c-ex2', 'e32895d6-daf1-479a-b571-55f690245a5c', 'assassination', 'The tribunal investigated the assassination as a politically motivated crime.', '法庭将这起暗杀作为出于政治动机的罪行进行调查。'),
  ('4fdaff71-b902-421d-81ab-a506541802bb-ex1', '4fdaff71-b902-421d-81ab-a506541802bb', 'assertion', 'His assertion turned out to be wrong.', '他的说法被证明是错误的。'),
  ('4fdaff71-b902-421d-81ab-a506541802bb-ex2', '4fdaff71-b902-421d-81ab-a506541802bb', 'assertion', 'The assertion of privilege was rejected under the crime-fraud exception.', '援引特权的主张依据犯罪欺诈例外被驳回。'),
  ('1552d044-e31b-46e2-933b-4f3533a3d516-ex1', '1552d044-e31b-46e2-933b-4f3533a3d516', 'assurance', 'She gave me her assurance that she would come.', '她向我保证她会来。'),
  ('1552d044-e31b-46e2-933b-4f3533a3d516-ex2', '1552d044-e31b-46e2-933b-4f3533a3d516', 'assurance', 'The auditor provides reasonable assurance, not an absolute guarantee.', '审计师提供的是合理保证，而非绝对担保。'),
  ('75a957ac-a048-4ab5-9145-c3c391c4d0f2-ex1', '75a957ac-a048-4ab5-9145-c3c391c4d0f2', 'coup', 'Signing that player was a real coup.', '签下那名球员实在是一大妙举。'),
  ('75a957ac-a048-4ab5-9145-c3c391c4d0f2-ex2', '75a957ac-a048-4ab5-9145-c3c391c4d0f2', 'coup', 'The coup suspended constitutional government and triggered international sanctions.', '这场政变中止了宪政，并引发国际制裁。'),
  ('c2070829-3e86-48c1-899d-6243baaf6247-ex1', 'c2070829-3e86-48c1-899d-6243baaf6247', 'astonishing', 'The view from the peak was astonishing.', '山顶的景色令人惊叹。'),
  ('c2070829-3e86-48c1-899d-6243baaf6247-ex2', 'c2070829-3e86-48c1-899d-6243baaf6247', 'astonishing', 'The concealment persisted for an astonishing twelve consecutive audit cycles.', '这一隐瞒行为竟持续了惊人的连续十二个审计周期。'),
  ('2555bb7e-bcd4-48db-a92d-4cb7138afb53-ex1', '2555bb7e-bcd4-48db-a92d-4cb7138afb53', 'asylum', 'The family applied for asylum.', '这家人申请了庇护。'),
  ('2555bb7e-bcd4-48db-a92d-4cb7138afb53-ex2', '2555bb7e-bcd4-48db-a92d-4cb7138afb53', 'asylum', 'Asylum claims must be adjudicated in accordance with due process.', '庇护申请必须按照正当程序进行裁决。'),
  ('617749c3-627f-45d1-8550-eb30b07ef12e-ex1', '617749c3-627f-45d1-8550-eb30b07ef12e', 'ambassador', 'The ambassador visited our school.', '大使访问了我们学校。'),
  ('617749c3-627f-45d1-8550-eb30b07ef12e-ex2', '617749c3-627f-45d1-8550-eb30b07ef12e', 'ambassador', 'The ambassador was recalled for consultations amid the escalating dispute.', '在争端不断升级之际，这位大使被召回国述职。'),
  ('57d3a63d-9de4-4e70-b0d0-b062c53871ca-ex1', '57d3a63d-9de4-4e70-b0d0-b062c53871ca', 'density', 'The city has a high population density.', '这座城市人口密度很高。'),
  ('57d3a63d-9de4-4e70-b0d0-b062c53871ca-ex2', '57d3a63d-9de4-4e70-b0d0-b062c53871ca', 'density', 'Zoning rules cap residential density within the heritage district.', '规划条例对历史街区内的住宅密度设定了上限。'),
  ('c55bdda8-e04d-4a7c-baf0-2e290fc3e64a-ex1', 'c55bdda8-e04d-4a7c-baf0-2e290fc3e64a', 'atrocity', 'The museum documents wartime atrocities.', '博物馆记录了战时暴行。'),
  ('c55bdda8-e04d-4a7c-baf0-2e290fc3e64a-ex2', 'c55bdda8-e04d-4a7c-baf0-2e290fc3e64a', 'atrocity', 'The tribunal prosecutes atrocities committed against civilian populations.', '该法庭起诉针对平民实施的暴行。'),
  ('8649ef3d-b250-40b9-b776-096a910d087b-ex1', '8649ef3d-b250-40b9-b776-096a910d087b', 'supportive', 'My parents are very supportive of my plans.', '我父母非常支持我的计划。'),
  ('8649ef3d-b250-40b9-b776-096a910d087b-ex2', '8649ef3d-b250-40b9-b776-096a910d087b', 'supportive', 'The committee proved supportive of reforms it had initially resisted.', '委员会对其最初抵制的改革最终转为支持。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('c941bbf3-a8cc-4ace-a669-c142a5078245-ex1', 'c941bbf3-a8cc-4ace-a669-c142a5078245', 'attachment', 'I sent the file as an attachment.', '我把文件作为附件发送了。'),
  ('c941bbf3-a8cc-4ace-a669-c142a5078245-ex2', 'c941bbf3-a8cc-4ace-a669-c142a5078245', 'attachment', 'The court ordered attachment of assets pending the fraud proceedings.', '在欺诈诉讼审结之前，法院下令查封资产。'),
  ('2ed3d08c-dd5c-4448-8452-55ea0cc7c9dd-ex1', '2ed3d08c-dd5c-4448-8452-55ea0cc7c9dd', 'attain', 'She attained her goal of running a marathon.', '她实现了跑完马拉松的目标。'),
  ('2ed3d08c-dd5c-4448-8452-55ea0cc7c9dd-ex2', '2ed3d08c-dd5c-4448-8452-55ea0cc7c9dd', 'attain', 'Few programs attain their stated objectives within the projected budget.', '很少有项目能在预算之内实现其既定目标。'),
  ('357048ac-25eb-49a3-8dd8-da9a7b0a41d5-ex1', '357048ac-25eb-49a3-8dd8-da9a7b0a41d5', 'curiosity', 'Cats are full of curiosity.', '猫充满好奇心。'),
  ('357048ac-25eb-49a3-8dd8-da9a7b0a41d5-ex2', '357048ac-25eb-49a3-8dd8-da9a7b0a41d5', 'curiosity', 'The disclosure was prompted less by duty than by public curiosity.', '这次披露与其说出于义务，不如说是迫于公众的好奇。'),
  ('1e675586-0415-496e-bd42-db06f2b774e4-ex1', '1e675586-0415-496e-bd42-db06f2b774e4', 'skip', 'Don''t skip breakfast.', '不要不吃早餐。'),
  ('1e675586-0415-496e-bd42-db06f2b774e4-ex2', '1e675586-0415-496e-bd42-db06f2b774e4', 'skip', 'The tribunal cannot simply skip the jurisdictional question and reach the merits.', '法庭不能跳过管辖权问题而径行审理实体问题。'),
  ('b571c9b6-2dcf-4a90-b3bb-4cf1776465b5-ex1', 'b571c9b6-2dcf-4a90-b3bb-4cf1776465b5', 'audio', 'The audio quality of the recording is poor.', '这段录音的音质很差。'),
  ('b571c9b6-2dcf-4a90-b3bb-4cf1776465b5-ex2', 'b571c9b6-2dcf-4a90-b3bb-4cf1776465b5', 'audio', 'The audio evidence was admitted after forensic authentication.', '这段音频证据经法证鉴定后被采纳。'),
  ('7e50b767-494e-4880-b158-856e7c471330-ex1', '7e50b767-494e-4880-b158-856e7c471330', 'august', 'We go on vacation in August.', '我们八月去度假。'),
  ('7e50b767-494e-4880-b158-856e7c471330-ex2', '7e50b767-494e-4880-b158-856e7c471330', 'august', 'The provisions enter into force on the first of August next year.', '这些条款于明年八月一日起生效。'),
  ('f9be6fb1-1e08-40f7-b53b-5758f3889d3b-ex1', 'f9be6fb1-1e08-40f7-b53b-5758f3889d3b', 'aggression', 'The dog showed no aggression at all.', '这只狗毫无攻击性。'),
