  ('3777b24b-b69d-495a-85b6-cfe9d1abb80c-ex2', '3777b24b-b69d-495a-85b6-cfe9d1abb80c', 'cling', 'Incumbents cling to exemptions the reform was designed to abolish.', '在位者死守着改革本欲废除的豁免。'),
  ('f729464a-dcea-427b-aa30-b57cb43bada2-ex1', 'f729464a-dcea-427b-aa30-b57cb43bada2', 'composer', 'The composer wrote music for films.', '这位作曲家为电影配乐。'),
  ('f729464a-dcea-427b-aa30-b57cb43bada2-ex2', 'f729464a-dcea-427b-aa30-b57cb43bada2', 'composer', 'The composer''s estate litigated the streaming royalties for a decade.', '这位作曲家的遗产管理方就流媒体版税诉讼了十年。'),
  ('2bfa7ecb-9d69-4fb5-bda5-d848512fe125-ex1', '2bfa7ecb-9d69-4fb5-bda5-d848512fe125', 'compulsory', 'School uniforms are compulsory here.', '这里必须穿校服。'),
  ('2bfa7ecb-9d69-4fb5-bda5-d848512fe125-ex2', '2bfa7ecb-9d69-4fb5-bda5-d848512fe125', 'compulsory', 'The compulsory licensing provisions yield only upon adequate compensation.', '强制许可条款仅在给予充分补偿时方可适用。'),
  ('d9baac65-f120-4c84-a5b4-d0ddf380fb6f-ex1', 'd9baac65-f120-4c84-a5b4-d0ddf380fb6f', 'isolated', 'The village is isolated in winter.', '这个村庄冬天与外界隔绝。'),
  ('d9baac65-f120-4c84-a5b4-d0ddf380fb6f-ex2', 'd9baac65-f120-4c84-a5b4-d0ddf380fb6f', 'isolated', 'The violations were systemic rather than isolated incidents.', '这些违规是系统性的，而非孤立事件。'),
  ('16461b9c-5a83-44ea-8874-fb6e9a5fda14-ex1', '16461b9c-5a83-44ea-8874-fb6e9a5fda14', 'compute', 'The program computes the total automatically.', '程序会自动计算总数。'),
  ('16461b9c-5a83-44ea-8874-fb6e9a5fda14-ex2', '16461b9c-5a83-44ea-8874-fb6e9a5fda14', 'compute', 'Damages are computed by reference to the loss actually sustained.', '损害赔偿按实际遭受的损失计算。'),
  ('aad21a2d-1acd-4172-83c9-a683302800ef-ex1', 'aad21a2d-1acd-4172-83c9-a683302800ef', 'blink', 'She didn''t even blink at the news.', '听到消息她连眼都没眨。'),
  ('aad21a2d-1acd-4172-83c9-a683302800ef-ex2', 'aad21a2d-1acd-4172-83c9-a683302800ef', 'blink', 'Neither side would blink as the default deadline approached.', '随着违约期限临近，双方都不肯让步。'),
  ('b470ef92-df95-4535-819e-ee0113a29fb0-ex1', 'b470ef92-df95-4535-819e-ee0113a29fb0', 'conceal', 'He tried to conceal his surprise.', '他试图掩饰自己的惊讶。'),
  ('b470ef92-df95-4535-819e-ee0113a29fb0-ex2', 'b470ef92-df95-4535-819e-ee0113a29fb0', 'conceal', 'The structures were designed to conceal liabilities from the auditors.', '这些架构的设计目的是向审计师隐瞒负债。'),
  ('cdecda29-c045-4522-8cb7-5edfa624809a-ex1', 'cdecda29-c045-4522-8cb7-5edfa624809a', 'suspicious', 'The package looked suspicious.', '这个包裹看起来可疑。'),
  ('cdecda29-c045-4522-8cb7-5edfa624809a-ex2', 'cdecda29-c045-4522-8cb7-5edfa624809a', 'suspicious', 'Banks must report suspicious transactions to the financial intelligence unit.', '银行必须向金融情报机构报告可疑交易。'),
  ('474f5222-a922-4308-a161-d67e2e5d1e7e-ex1', '474f5222-a922-4308-a161-d67e2e5d1e7e', 'wheelchair', 'The library has wheelchair access.', '图书馆设有轮椅通道。'),
  ('474f5222-a922-4308-a161-d67e2e5d1e7e-ex2', '474f5222-a922-4308-a161-d67e2e5d1e7e', 'wheelchair', 'The code mandates wheelchair accessibility in all public accommodations.', '规范要求所有公共场所具备轮椅无障碍条件。'),
  ('fe10c960-3e3b-4d68-8d84-27e42ad4afc8-ex1', 'fe10c960-3e3b-4d68-8d84-27e42ad4afc8', 'concession', 'Each side made concessions to reach a deal.', '双方各作让步达成了协议。'),
  ('fe10c960-3e3b-4d68-8d84-27e42ad4afc8-ex2', 'fe10c960-3e3b-4d68-8d84-27e42ad4afc8', 'concession', 'The mining concession reverts to the state upon expiry of the term.', '采矿特许权在期限届满后归还国家。'),
  ('56a9f74b-5358-4061-8da1-cb6c03ae791f-ex1', '56a9f74b-5358-4061-8da1-cb6c03ae791f', 'squad', 'He made the school football squad.', '他入选了校足球队。'),
  ('56a9f74b-5358-4061-8da1-cb6c03ae791f-ex2', '56a9f74b-5358-4061-8da1-cb6c03ae791f', 'squad', 'The fraud squad executed simultaneous warrants across three cities.', '反诈专案组在三座城市同时执行了搜查令。'),
  ('a61bf2b9-8c7e-4bfc-8aaf-226b4da67891-ex1', 'a61bf2b9-8c7e-4bfc-8aaf-226b4da67891', 'confer', 'The two leaders conferred for an hour.', '两位领导人商谈了一个小时。'),
  ('a61bf2b9-8c7e-4bfc-8aaf-226b4da67891-ex2', 'a61bf2b9-8c7e-4bfc-8aaf-226b4da67891', 'confer', 'The statute confers upon the agency only the powers expressly enumerated.', '该法规仅授予机构明文列举的权力。'),
  ('5ca53132-72af-4238-97ae-793a646cdb9b-ex1', '5ca53132-72af-4238-97ae-793a646cdb9b', 'confine', 'Please confine your remarks to the topic.', '请把发言限制在主题范围内。'),
  ('5ca53132-72af-4238-97ae-793a646cdb9b-ex2', '5ca53132-72af-4238-97ae-793a646cdb9b', 'confine', 'The ruling confines the precedent to its materially distinct facts.', '该裁决将先例限定于其具有重大区别的事实。'),
  ('b11bdea7-bafb-40f8-bb73-6fc700c26b6d-ex1', 'b11bdea7-bafb-40f8-bb73-6fc700c26b6d', 'eligible', 'You are eligible for a student discount.', '你有资格享受学生优惠。'),
  ('b11bdea7-bafb-40f8-bb73-6fc700c26b6d-ex2', 'b11bdea7-bafb-40f8-bb73-6fc700c26b6d', 'eligible', 'Only claimants meeting every criterion are eligible for expedited settlement.', '只有满足全部标准的索赔人才有资格获得快速和解。'),
  ('88c7d84d-3c34-4389-83a6-34b42de33006-ex1', '88c7d84d-3c34-4389-83a6-34b42de33006', 'confirmation', 'We received confirmation of our booking.', '我们收到了预订确认。'),
  ('88c7d84d-3c34-4389-83a6-34b42de33006-ex2', '88c7d84d-3c34-4389-83a6-34b42de33006', 'confirmation', 'The confirmation hearing examined the nominee''s record exhaustively.', '任命确认听证会详尽审查了被提名人的过往记录。'),
  ('9db74088-f367-498d-9c94-8d55adddf312-ex1', '9db74088-f367-498d-9c94-8d55adddf312', 'processor', 'The new phone has a faster processor.', '新手机的处理器更快。'),
  ('9db74088-f367-498d-9c94-8d55adddf312-ex2', '9db74088-f367-498d-9c94-8d55adddf312', 'processor', 'Data processors bear obligations distinct from those of controllers.', '数据处理者承担与数据控制者不同的义务。'),
  ('a50b9615-4bc1-47fe-be55-be48e74a5943-ex1', 'a50b9615-4bc1-47fe-be55-be48e74a5943', 'plunge', 'He took a plunge into the cold lake.', '他一头扎进冰冷的湖水。'),
  ('a50b9615-4bc1-47fe-be55-be48e74a5943-ex2', 'a50b9615-4bc1-47fe-be55-be48e74a5943', 'plunge', 'The shares plunged as the restatement''s magnitude became apparent.', '随着财报重述的规模显现，股价应声暴跌。'),
  ('f7c141a0-ac65-4f5e-8665-9a6e367361d6-ex1', 'f7c141a0-ac65-4f5e-8665-9a6e367361d6', 'confused', 'I am confused by these instructions.', '这些说明让我很困惑。'),
  ('f7c141a0-ac65-4f5e-8665-9a6e367361d6-ex2', 'f7c141a0-ac65-4f5e-8665-9a6e367361d6', 'confused', 'The jury was confused by instructions the appellate court found misleading.', '陪审团被上诉法院认定具有误导性的指示弄糊涂了。'),
  ('711cd453-f8d9-47bd-a2b1-e91d04a56b1f-ex1', '711cd453-f8d9-47bd-a2b1-e91d04a56b1f', 'confusing', 'The map is confusing without street names.', '没有街名的地图让人摸不着头脑。'),
  ('711cd453-f8d9-47bd-a2b1-e91d04a56b1f-ex2', '711cd453-f8d9-47bd-a2b1-e91d04a56b1f', 'confusing', 'The overlapping mandates created a confusing patchwork of authority.', '职权的重叠造成了权责混乱交错的局面。'),
  ('85c86ce4-e9b4-4bed-8727-ff67c03c6804-ex1', '85c86ce4-e9b4-4bed-8727-ff67c03c6804', 'congratulate', 'Let me congratulate you on your success!', '祝贺你取得成功！'),
  ('85c86ce4-e9b4-4bed-8727-ff67c03c6804-ex2', '85c86ce4-e9b4-4bed-8727-ff67c03c6804', 'congratulate', 'The secretariat congratulated member states on achieving full ratification.', '秘书处祝贺成员国实现全面批准。'),
  ('9753e6b7-e603-438a-ae2e-9ea9541779c9-ex1', '9753e6b7-e603-438a-ae2e-9ea9541779c9', 'congregation', 'The congregation sang together.', '会众齐声歌唱。'),
  ('9753e6b7-e603-438a-ae2e-9ea9541779c9-ex2', '9753e6b7-e603-438a-ae2e-9ea9541779c9', 'congregation', 'The congregation''s charitable status was reviewed for political activity.', '该会众团体的慈善资格因政治活动而受到审查。'),
  ('5e90da4a-ba7b-464c-aff7-290ebc3d3f9a-ex1', '5e90da4a-ba7b-464c-aff7-290ebc3d3f9a', 'connected', 'The two rooms are connected by a door.', '这两个房间由一扇门相通。'),
  ('5e90da4a-ba7b-464c-aff7-290ebc3d3f9a-ex2', '5e90da4a-ba7b-464c-aff7-290ebc3d3f9a', 'connected', 'The transactions were connected parties dealings requiring disclosure.', '这些交易属于须予披露的关联方往来。'),
  ('11325c53-8627-4da4-89ef-9f70bf9be0b4-ex1', '11325c53-8627-4da4-89ef-9f70bf9be0b4', 'conquer', 'She conquered her fear of heights.', '她克服了恐高症。'),
  ('11325c53-8627-4da4-89ef-9f70bf9be0b4-ex2', '11325c53-8627-4da4-89ef-9f70bf9be0b4', 'conquer', 'No enforcement regime can conquer evasion without international cooperation.', '没有国际合作，任何执法体制都无法战胜规避行为。'),
  ('23ba1627-5f63-4b58-846d-932661d9ee52-ex1', '23ba1627-5f63-4b58-846d-932661d9ee52', 'demographic', 'The app is popular with a young demographic.', '这款应用在年轻群体中很受欢迎。'),
  ('23ba1627-5f63-4b58-846d-932661d9ee52-ex2', '23ba1627-5f63-4b58-846d-932661d9ee52', 'demographic', 'Demographic decline constrains long-term growth across the region.', '人口下滑制约着该地区的长期增长。'),
  ('0389f233-b274-423f-be0b-d9535cba4ae7-ex1', '0389f233-b274-423f-be0b-d9535cba4ae7', 'conserve', 'Turn off lights to conserve energy.', '随手关灯节约能源。'),
  ('0389f233-b274-423f-be0b-d9535cba4ae7-ex2', '0389f233-b274-423f-be0b-d9535cba4ae7', 'conserve', 'The easement obliges the owner to conserve the habitat in perpetuity.', '地役权要求所有人永久保护这片栖息地。'),
  ('ff532fa9-0b75-45ca-87b5-bfc619d5904a-ex1', 'ff532fa9-0b75-45ca-87b5-bfc619d5904a', 'consistency', 'Practice with consistency brings progress.', '持之以恒的练习带来进步。'),
  ('ff532fa9-0b75-45ca-87b5-bfc619d5904a-ex2', 'ff532fa9-0b75-45ca-87b5-bfc619d5904a', 'consistency', 'Consistency in enforcement underpins the legitimacy of the entire regime.', '执法的一致性是整个制度公信力的基础。'),
  ('ffd530c1-4828-4ae0-808d-793b657adfdf-ex1', 'ffd530c1-4828-4ae0-808d-793b657adfdf', 'chill', 'There is a chill in the morning air.', '清晨的空气透着寒意。'),
  ('ffd530c1-4828-4ae0-808d-793b657adfdf-ex2', 'ffd530c1-4828-4ae0-808d-793b657adfdf', 'chill', 'The ruling cast a chill over investigative reporting nationwide.', '这一裁决给全国的调查报道蒙上了寒蝉效应。'),
  ('3f680d1f-e114-4be9-98b9-28ac433d7db6-ex1', '3f680d1f-e114-4be9-98b9-28ac433d7db6', 'refuge', 'We took refuge from the rain in a cafe.', '我们在咖啡馆里避雨。'),
  ('3f680d1f-e114-4be9-98b9-28ac433d7db6-ex2', '3f680d1f-e114-4be9-98b9-28ac433d7db6', 'refuge', 'Tax havens offer refuge to capital seeking to escape scrutiny.', '避税港为逃避审查的资本提供了庇护所。'),
  ('f38245fe-2d9e-4884-89a5-e98792d21da0-ex1', 'f38245fe-2d9e-4884-89a5-e98792d21da0', 'consolidate', 'The two schools will consolidate next year.', '两所学校明年将合并。'),
  ('f38245fe-2d9e-4884-89a5-e98792d21da0-ex2', 'f38245fe-2d9e-4884-89a5-e98792d21da0', 'consolidate', 'The statute consolidates fragmented procedures into a unified framework.', '该法规将零散的程序整合为统一框架。'),
  ('4f8ed371-7524-4a2b-8dc2-96c335fc098d-ex1', '4f8ed371-7524-4a2b-8dc2-96c335fc098d', 'steer', 'He steered the boat toward the shore.', '他把船驶向岸边。'),
  ('4f8ed371-7524-4a2b-8dc2-96c335fc098d-ex2', '4f8ed371-7524-4a2b-8dc2-96c335fc098d', 'steer', 'The chair steered the negotiations away from the most divisive issues.', '主席引导谈判避开了最具分歧的议题。'),
  ('7d806abf-2c1b-45a9-8633-bd7a092148e7-ex1', '7d806abf-2c1b-45a9-8633-bd7a092148e7', 'consultation', 'The doctor offers free consultations.', '这位医生提供免费问诊。'),
  ('7d806abf-2c1b-45a9-8633-bd7a092148e7-ex2', '7d806abf-2c1b-45a9-8633-bd7a092148e7', 'consultation', 'The permit was quashed for failure to conduct meaningful consultation.', '该许可因未进行实质性磋商而被撤销。'),
  ('0487fa5f-ba9e-4dba-b0eb-bdd9b4c24572-ex1', '0487fa5f-ba9e-4dba-b0eb-bdd9b4c24572', 'contempt', 'He showed contempt for the rules.', '他对规则不屑一顾。'),
  ('0487fa5f-ba9e-4dba-b0eb-bdd9b4c24572-ex2', '0487fa5f-ba9e-4dba-b0eb-bdd9b4c24572', 'contempt', 'Persistent noncompliance exposed the firm to contempt proceedings.', '持续不履行使该公司面临藐视法庭程序。'),
  ('8e32fe7d-2924-4a1c-87b8-b0ab414c84f5-ex1', '8e32fe7d-2924-4a1c-87b8-b0ab414c84f5', 'legislator', 'The legislators debated the new law.', '立法者们就新法律进行了辩论。'),
  ('8e32fe7d-2924-4a1c-87b8-b0ab414c84f5-ex2', '8e32fe7d-2924-4a1c-87b8-b0ab414c84f5', 'legislator', 'Legislators inserted the exemption during the conference reconciliation.', '立法者在两院协商阶段加入了这项豁免。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('4e62c967-6441-4f3a-892b-277200386249-ex1', '4e62c967-6441-4f3a-892b-277200386249', 'rally', 'Thousands attended the rally downtown.', '数千人参加了市中心的集会。'),
  ('4e62c967-6441-4f3a-892b-277200386249-ex2', '4e62c967-6441-4f3a-892b-277200386249', 'rally', 'Markets rallied once the emergency facility was announced.', '紧急融资安排一经宣布，市场应声反弹。'),
  ('e5a2feab-95dd-4d83-86c6-b0bef69f8ad0-ex1', 'e5a2feab-95dd-4d83-86c6-b0bef69f8ad0', 'contender', 'She is a strong contender for the prize.', '她是该奖项的有力竞争者。'),
  ('e5a2feab-95dd-4d83-86c6-b0bef69f8ad0-ex2', 'e5a2feab-95dd-4d83-86c6-b0bef69f8ad0', 'contender', 'The merger eliminated the only credible contender in the regional market.', '此次合并消灭了区域市场上唯一有实力的竞争者。'),
  ('8ba217d2-a637-4355-aa0c-74f326272ea4-ex1', '8ba217d2-a637-4355-aa0c-74f326272ea4', 'contention', 'His contention is that the plan costs too much.', '他的论点是该计划成本过高。'),
  ('8ba217d2-a637-4355-aa0c-74f326272ea4-ex2', '8ba217d2-a637-4355-aa0c-74f326272ea4', 'contention', 'The central contention concerns the construction of the indemnity clause.', '核心争点在于赔偿条款的解释。'),
  ('ed39a68c-0b26-4121-8c55-b67ae1acbff5-ex1', 'ed39a68c-0b26-4121-8c55-b67ae1acbff5', 'programming', 'She is learning computer programming.', '她在学习计算机编程。'),
  ('ed39a68c-0b26-4121-8c55-b67ae1acbff5-ex2', 'ed39a68c-0b26-4121-8c55-b67ae1acbff5', 'programming', 'The broadcaster''s programming obligations are conditions of its licence.', '该广播机构的节目义务是其牌照的附带条件。'),
  ('0ef42ee0-5d6f-4e75-bb7e-cbfa9ac4aa6a-ex1', '0ef42ee0-5d6f-4e75-bb7e-cbfa9ac4aa6a', 'cheer', 'The crowd cheered for the home team.', '观众为主队欢呼。'),
  ('0ef42ee0-5d6f-4e75-bb7e-cbfa9ac4aa6a-ex2', '0ef42ee0-5d6f-4e75-bb7e-cbfa9ac4aa6a', 'cheer', 'The settlement gave claimants little to cheer beyond symbolic vindication.', '除了象征性的正名，这份和解几乎没给索赔人带来什么可喜之处。'),
  ('9bfe3120-91fc-4720-8628-8db44396c483-ex1', '9bfe3120-91fc-4720-8628-8db44396c483', 'continually', 'The baby cried continually all night.', '宝宝整夜哭个不停。'),
  ('9bfe3120-91fc-4720-8628-8db44396c483-ex2', '9bfe3120-91fc-4720-8628-8db44396c483', 'continually', 'Risk models must be continually recalibrated as conditions evolve.', '随着形势变化，风险模型必须不断重新校准。'),
  ('47593c58-7bdf-4785-b6fd-11657b1d7d1f-ex1', '47593c58-7bdf-4785-b6fd-11657b1d7d1f', 'contradiction', 'His story is full of contradictions.', '他的说法漏洞百出、自相矛盾。'),
  ('47593c58-7bdf-4785-b6fd-11657b1d7d1f-ex2', '47593c58-7bdf-4785-b6fd-11657b1d7d1f', 'contradiction', 'The testimony stands in flat contradiction to the documentary record.', '这份证词与书面记录截然矛盾。'),
  ('ee2d59ab-f619-452f-b25a-445e64a48fbd-ex1', 'ee2d59ab-f619-452f-b25a-445e64a48fbd', 'outlet', 'Sports are a good outlet for energy.', '运动是释放精力的好途径。'),
  ('ee2d59ab-f619-452f-b25a-445e64a48fbd-ex2', 'ee2d59ab-f619-452f-b25a-445e64a48fbd', 'outlet', 'Media outlets face liability for republishing the defamatory material.', '媒体机构因转载诽谤材料而面临责任。'),
  ('28ff3171-36b9-40d0-88fe-e6e434b0b33b-ex1', '28ff3171-36b9-40d0-88fe-e6e434b0b33b', 'contrary', 'Contrary to the forecast, it stayed sunny.', '与预报相反，天气一直晴朗。'),
  ('28ff3171-36b9-40d0-88fe-e6e434b0b33b-ex2', '28ff3171-36b9-40d0-88fe-e6e434b0b33b', 'contrary', 'Absent agreement to the contrary, the default statutory rules apply.', '如无相反约定，适用法定默认规则。'),
  ('bda0ef52-dc4d-4456-83f3-c51a4f88c986-ex1', 'bda0ef52-dc4d-4456-83f3-c51a4f88c986', 'intact', 'The package arrived intact.', '包裹完好无损地送达。'),
