  ('f6386648-b87a-4728-abe1-23ccf1bd0caa-ex2', 'f6386648-b87a-4728-abe1-23ccf1bd0caa', 'lawmaker', 'Lawmakers inserted the exemption during the closing hours of the session.', '立法者在会期最后时刻塞入了这项豁免。'),
  ('2fdaa678-06ad-4a13-9b74-61806bea3293-ex1', '2fdaa678-06ad-4a13-9b74-61806bea3293', 'supermarket', 'I bought milk at the supermarket.', '我在超市买了牛奶。'),
  ('2fdaa678-06ad-4a13-9b74-61806bea3293-ex2', '2fdaa678-06ad-4a13-9b74-61806bea3293', 'supermarket', 'The supermarket chains face scrutiny over supplier payment practices.', '连锁超市因供应商付款惯例而受到审查。'),
  ('92b92067-c5c3-4a3a-9ded-58acf08fe66e-ex1', '92b92067-c5c3-4a3a-9ded-58acf08fe66e', 'deprive', 'Don''t deprive yourself of sleep.', '不要剥夺自己的睡眠。'),
  ('92b92067-c5c3-4a3a-9ded-58acf08fe66e-ex2', '92b92067-c5c3-4a3a-9ded-58acf08fe66e', 'deprive', 'No person may be deprived of liberty without due process of law.', '未经正当法律程序，任何人不得被剥夺自由。'),
