  ('6cae149a-cdb1-4f8f-bcf0-d6cef8c244d7-ex2', '6cae149a-cdb1-4f8f-bcf0-d6cef8c244d7', 'calendar', 'The court''s calendar delays adjudication by years in complex matters.', '法院的排期使复杂案件的审理延宕数年。'),
  ('0eb7b352-53fe-4817-8f33-b69bcfb48f68-ex1', '0eb7b352-53fe-4817-8f33-b69bcfb48f68', 'detection', 'Early detection saves lives.', '早期发现能挽救生命。'),
  ('0eb7b352-53fe-4817-8f33-b69bcfb48f68-ex2', '0eb7b352-53fe-4817-8f33-b69bcfb48f68', 'detection', 'The system''s detection thresholds missed transactions structured below them.', '系统的侦测阈值漏掉了刻意设计在阈值之下的交易。'),
  ('656120d0-18a1-48c5-a009-25da1d7bf355-ex1', '656120d0-18a1-48c5-a009-25da1d7bf355', 'widow', 'The widow lives with her daughter.', '这位遗孀和女儿住在一起。'),
  ('656120d0-18a1-48c5-a009-25da1d7bf355-ex2', '656120d0-18a1-48c5-a009-25da1d7bf355', 'widow', 'The pension provisions entitle the widow to benefits accrued during marriage.', '养老金条款赋予遗孀获得婚姻存续期间累积待遇的权利。'),
  ('74ddb5fe-6822-49a1-b9f1-c8771b66a432-ex1', '74ddb5fe-6822-49a1-b9f1-c8771b66a432', 'deposit', 'You need to pay a deposit for the room.', '订房间需要付押金。'),
  ('74ddb5fe-6822-49a1-b9f1-c8771b66a432-ex2', '74ddb5fe-6822-49a1-b9f1-c8771b66a432', 'deposit', 'Deposit insurance stems runs but breeds moral hazard in equal measure.', '存款保险能遏制挤兑，却同样滋生道德风险。'),
  ('fbfa7704-614f-4373-9034-a91da85806ed-ex1', 'fbfa7704-614f-4373-9034-a91da85806ed', 'deteriorate', 'His health began to deteriorate.', '他的健康状况开始恶化。'),
  ('fbfa7704-614f-4373-9034-a91da85806ed-ex2', 'fbfa7704-614f-4373-9034-a91da85806ed', 'deteriorate', 'Conditions deteriorated faster than the contingency triggers could respond.', '形势恶化的速度超过了应急触发机制的响应能力。'),
  ('592bb4b7-0712-4c51-9ed2-fca8d98d934c-ex1', '592bb4b7-0712-4c51-9ed2-fca8d98d934c', 'determined', 'She is determined to finish the race.', '她决心跑完比赛。'),
  ('592bb4b7-0712-4c51-9ed2-fca8d98d934c-ex2', '592bb4b7-0712-4c51-9ed2-fca8d98d934c', 'determined', 'The quantum of loss is determined by reference to market value at breach.', '损失数额参照违约时的市场价值确定。'),
  ('8b833204-99a2-42ea-a154-b6fec5c6ae46-ex1', '8b833204-99a2-42ea-a154-b6fec5c6ae46', 'beard', 'He grew a beard over the winter.', '他留了一个冬天的胡子。'),
  ('8b833204-99a2-42ea-a154-b6fec5c6ae46-ex2', '8b833204-99a2-42ea-a154-b6fec5c6ae46', 'beard', 'The witness''s altered beard complicated the identification evidence.', '证人胡须的变化使辨认证据复杂化。'),
  ('3838a216-6fe9-4cca-b21f-913413276e10-ex1', '3838a216-6fe9-4cca-b21f-913413276e10', 'brake', 'Check the brakes before driving.', '开车前检查刹车。'),
