  ('d0c2c7b4-5e0d-47c9-8eed-5705a28a1f7c-ex2', 'd0c2c7b4-5e0d-47c9-8eed-5705a28a1f7c', 'disposal', 'The directive regulates transboundary disposal of hazardous waste.', '该指令规范危险废物的跨境处置。'),
  ('c6e8082e-0b44-4729-8001-2bab4da33b04-ex1', 'c6e8082e-0b44-4729-8001-2bab4da33b04', 'thread', 'I need a needle and thread.', '我需要针和线。'),
  ('c6e8082e-0b44-4729-8001-2bab4da33b04-ex2', 'c6e8082e-0b44-4729-8001-2bab4da33b04', 'thread', 'A common thread of concealment runs through every count of the indictment.', '隐瞒这条主线贯穿起诉书的每一项罪名。'),
  ('f5f3f971-cdfd-4078-83be-ca2051626453-ex1', 'f5f3f971-cdfd-4078-83be-ca2051626453', 'dispose', 'Dispose of the trash properly.', '妥善处理垃圾。'),
  ('f5f3f971-cdfd-4078-83be-ca2051626453-ex2', 'f5f3f971-cdfd-4078-83be-ca2051626453', 'dispose', 'The trustee may not dispose of estate assets absent court approval.', '未经法院批准，受托人不得处置遗产资产。'),
  ('541f4042-73ec-45d8-b035-97f0d4fef5c9-ex1', '541f4042-73ec-45d8-b035-97f0d4fef5c9', 'disrupt', 'The noise disrupted the class.', '噪音扰乱了课堂。'),
  ('541f4042-73ec-45d8-b035-97f0d4fef5c9-ex2', '541f4042-73ec-45d8-b035-97f0d4fef5c9', 'disrupt', 'The cyberattack disrupted settlement systems across three markets.', '网络攻击扰乱了三个市场的结算系统。'),
  ('a1983d66-338d-4c35-9841-0ec17cc459c0-ex1', 'a1983d66-338d-4c35-9841-0ec17cc459c0', 'disruption', 'The storm caused travel disruption.', '暴风雨造成了交通中断。'),
  ('a1983d66-338d-4c35-9841-0ec17cc459c0-ex2', 'a1983d66-338d-4c35-9841-0ec17cc459c0', 'disruption', 'Supply disruption propagated through tightly coupled production networks.', '供应中断沿着紧密耦合的生产网络层层传导。'),
  ('e7e0cdde-5781-4527-a147-4bb5b420a81a-ex1', 'e7e0cdde-5781-4527-a147-4bb5b420a81a', 'landmark', 'The tower is the city''s famous landmark.', '这座塔是该市著名的地标。'),
  ('e7e0cdde-5781-4527-a147-4bb5b420a81a-ex2', 'e7e0cdde-5781-4527-a147-4bb5b420a81a', 'landmark', 'The landmark ruling redefined the boundaries of platform liability.', '这一里程碑式的裁决重新界定了平台责任的边界。'),
  ('318e5d5e-9b81-4527-8a16-7bce91217a61-ex1', '318e5d5e-9b81-4527-8a16-7bce91217a61', 'distort', 'The mirror distorts your reflection.', '这面镜子会使影像变形。'),
  ('318e5d5e-9b81-4527-8a16-7bce91217a61-ex2', '318e5d5e-9b81-4527-8a16-7bce91217a61', 'distort', 'Implicit guarantees distort risk pricing across the entire sector.', '隐性担保扭曲了整个行业的风险定价。'),
  ('b43d1fc2-c39b-4c65-8c37-15c52a97be8e-ex1', 'b43d1fc2-c39b-4c65-8c37-15c52a97be8e', 'unhappy', 'She looked unhappy with the result.', '她对结果显得不满意。'),
  ('b43d1fc2-c39b-4c65-8c37-15c52a97be8e-ex2', 'b43d1fc2-c39b-4c65-8c37-15c52a97be8e', 'unhappy', 'Unhappy creditors challenged the plan as unfairly discriminatory.', '心怀不满的债权人以不公平歧视为由质疑该方案。'),
  ('43fe091c-71c7-4232-a818-8b3252b689c6-ex1', '43fe091c-71c7-4232-a818-8b3252b689c6', 'distress', 'The lost child was in obvious distress.', '走失的孩子显然惊恐不安。'),
  ('43fe091c-71c7-4232-a818-8b3252b689c6-ex2', '43fe091c-71c7-4232-a818-8b3252b689c6', 'distress', 'The doctrine relieves parties who contract under economic distress.', '该原则为在经济困迫下缔约的当事人提供救济。'),
  ('e1483979-b7a0-43c8-adfd-3c4ea5c6f119-ex1', 'e1483979-b7a0-43c8-adfd-3c4ea5c6f119', 'offender', 'First-time offenders received a warning.', '初犯者收到了警告。'),
  ('e1483979-b7a0-43c8-adfd-3c4ea5c6f119-ex2', 'e1483979-b7a0-43c8-adfd-3c4ea5c6f119', 'offender', 'The register tracks offenders subject to continuing reporting obligations.', '登记系统追踪负有持续报告义务的违法者。'),
  ('0be57f28-9588-48c5-8470-3c1f13c12f20-ex1', '0be57f28-9588-48c5-8470-3c1f13c12f20', 'dive', 'She dove into the pool gracefully.', '她优雅地跳入泳池。'),
  ('0be57f28-9588-48c5-8470-3c1f13c12f20-ex2', '0be57f28-9588-48c5-8470-3c1f13c12f20', 'dive', 'The shares took a dive as the restatement''s scale emerged.', '随着财报重述规模的曝光，股价应声跳水。'),
  ('8e913b53-9cec-40d1-83d3-31daa94ccaf9-ex1', '8e913b53-9cec-40d1-83d3-31daa94ccaf9', 'coming', 'The coming winter will be cold.', '即将到来的冬天会很冷。'),
  ('8e913b53-9cec-40d1-83d3-31daa94ccaf9-ex2', '8e913b53-9cec-40d1-83d3-31daa94ccaf9', 'coming', 'The coming review will test the framework''s resilience comprehensively.', '即将进行的审查将全面检验该框架的韧性。'),
  ('2a710d85-07fc-48a9-ba80-04119150cb52-ex1', '2a710d85-07fc-48a9-ba80-04119150cb52', 'divert', 'They diverted the river around the town.', '他们让河流改道绕过城镇。'),
  ('2a710d85-07fc-48a9-ba80-04119150cb52-ex2', '2a710d85-07fc-48a9-ba80-04119150cb52', 'divert', 'Funds were diverted from their appropriated purpose without authorization.', '资金在未经授权的情况下被挪离其拨款用途。'),
  ('fdb627a3-05f6-46db-9716-30d6e6c57169-ex1', 'fdb627a3-05f6-46db-9716-30d6e6c57169', 'privately', 'They discussed the matter privately.', '他们私下讨论了这件事。'),
  ('fdb627a3-05f6-46db-9716-30d6e6c57169-ex2', 'fdb627a3-05f6-46db-9716-30d6e6c57169', 'privately', 'The undertakings were negotiated privately and never publicly disclosed.', '这些承诺是私下协商达成的，从未公开披露。'),
  ('3c318379-f266-4486-bd9e-85e717261e44-ex1', '3c318379-f266-4486-bd9e-85e717261e44', 'fraction', 'Only a fraction of the students attended.', '只有一小部分学生出席。'),
  ('3c318379-f266-4486-bd9e-85e717261e44-ex2', '3c318379-f266-4486-bd9e-85e717261e44', 'fraction', 'Claimants recovered a fraction of the losses the fraud inflicted.', '索赔人仅追回了欺诈所致损失的一小部分。'),
  ('a5311aac-536b-4605-9193-b86915718ad2-ex1', 'a5311aac-536b-4605-9193-b86915718ad2', 'divorced', 'Her parents are divorced.', '她的父母离婚了。'),
  ('a5311aac-536b-4605-9193-b86915718ad2-ex2', 'a5311aac-536b-4605-9193-b86915718ad2', 'divorced', 'The projections were wholly divorced from any defensible assumption.', '这些预测完全脱离了任何站得住脚的假设。'),
  ('2cf79dc4-1945-493f-9ad8-db47f9252050-ex1', '2cf79dc4-1945-493f-9ad8-db47f9252050', 'distinctive', 'The bird has a distinctive song.', '这种鸟的叫声很有辨识度。'),
  ('2cf79dc4-1945-493f-9ad8-db47f9252050-ex2', '2cf79dc4-1945-493f-9ad8-db47f9252050', 'distinctive', 'Trademark protection requires that the mark be distinctive, not descriptive.', '商标保护要求标识具有显著性，而非描述性。'),
  ('92300d22-3546-44d7-8dac-14ebe041754d-ex1', '92300d22-3546-44d7-8dac-14ebe041754d', 'dollar', 'The book costs ten dollars.', '这本书十美元。'),
  ('92300d22-3546-44d7-8dac-14ebe041754d-ex2', '92300d22-3546-44d7-8dac-14ebe041754d', 'dollar', 'Dollar funding stress propagated through offshore banking networks.', '美元融资压力通过离岸银行网络层层传导。'),
  ('83ec5b8c-768b-40e4-ae30-28125d388389-ex1', '83ec5b8c-768b-40e4-ae30-28125d388389', 'tourism', 'Tourism is the island''s main industry.', '旅游业是这座岛的主要产业。'),
  ('83ec5b8c-768b-40e4-ae30-28125d388389-ex2', '83ec5b8c-768b-40e4-ae30-28125d388389', 'tourism', 'The tourism levy funds conservation of the sites visitors frequent.', '旅游税为游客常去景点的保护提供资金。'),
  ('d7683c58-a9d6-4b82-a788-00dce2b08bb4-ex1', 'd7683c58-a9d6-4b82-a788-00dce2b08bb4', 'dominance', 'The team showed total dominance in the final.', '这支球队在决赛中展现了绝对统治力。'),
  ('d7683c58-a9d6-4b82-a788-00dce2b08bb4-ex2', 'd7683c58-a9d6-4b82-a788-00dce2b08bb4', 'dominance', 'Abuse of market dominance attracts structural as well as behavioral remedies.', '滥用市场支配地位会招致结构性和行为性救济。'),
  ('657a509e-2c32-45ef-98d9-7b1eee32979f-ex1', '657a509e-2c32-45ef-98d9-7b1eee32979f', 'threshold', 'He carried the box over the threshold.', '他抱着箱子跨过门槛。'),
  ('657a509e-2c32-45ef-98d9-7b1eee32979f-ex2', '657a509e-2c32-45ef-98d9-7b1eee32979f', 'threshold', 'Transactions below the reporting threshold escaped scrutiny entirely.', '低于申报门槛的交易完全逃过了审查。'),
  ('d56909a7-e24a-419b-8a31-d2755e80a585-ex1', 'd56909a7-e24a-419b-8a31-d2755e80a585', 'download', 'You can download the app for free.', '你可以免费下载这个应用。'),
  ('d56909a7-e24a-419b-8a31-d2755e80a585-ex2', 'd56909a7-e24a-419b-8a31-d2755e80a585', 'download', 'Unauthorized downloads of the protected work grounded the infringement claim.', '对受保护作品的未授权下载构成了侵权主张的基础。'),
  ('dcf5f8f0-2edc-441f-ba08-4c8a8a15c23b-ex1', 'dcf5f8f0-2edc-441f-ba08-4c8a8a15c23b', 'downstairs', 'The kitchen is downstairs.', '厨房在楼下。'),
  ('dcf5f8f0-2edc-441f-ba08-4c8a8a15c23b-ex2', 'dcf5f8f0-2edc-441f-ba08-4c8a8a15c23b', 'downstairs', 'The archive was relocated downstairs to a climate-controlled vault.', '档案被移至楼下一间恒温恒湿的库房。'),
  ('1ea71297-850a-4450-865a-2ecbbfae1c0d-ex1', '1ea71297-850a-4450-865a-2ecbbfae1c0d', 'routinely', 'She routinely checks her email at dawn.', '她习惯一早查看邮件。'),
  ('1ea71297-850a-4450-865a-2ecbbfae1c0d-ex2', '1ea71297-850a-4450-865a-2ecbbfae1c0d', 'routinely', 'The thresholds were routinely circumvented through transaction structuring.', '这些门槛经常被通过交易结构化设计加以规避。'),
  ('912b883c-ba5a-40ac-8a10-55852e65c6d6-ex1', '912b883c-ba5a-40ac-8a10-55852e65c6d6', 'downward', 'The path slopes downward to the lake.', '小路向下通往湖边。'),
  ('912b883c-ba5a-40ac-8a10-55852e65c6d6-ex2', '912b883c-ba5a-40ac-8a10-55852e65c6d6', 'downward', 'The downward revision of growth forecasts compelled fiscal recalibration.', '增长预测的下调迫使财政政策重新校准。'),
  ('746becf0-d764-4c94-aa18-c39362a72826-ex1', '746becf0-d764-4c94-aa18-c39362a72826', 'suite', 'They booked a suite for the weekend.', '他们订了一间周末套房。'),
  ('746becf0-d764-4c94-aa18-c39362a72826-ex2', '746becf0-d764-4c94-aa18-c39362a72826', 'suite', 'The directive introduces a suite of remedies calibrated to violation severity.', '该指令引入了一整套按违规严重程度调配的救济措施。'),
  ('f4dd23f3-c85c-426e-80ae-cb5aacb2b725-ex1', 'f4dd23f3-c85c-426e-80ae-cb5aacb2b725', 'dressed', 'She was dressed in blue.', '她身穿蓝色衣服。'),
  ('f4dd23f3-c85c-426e-80ae-cb5aacb2b725-ex2', 'f4dd23f3-c85c-426e-80ae-cb5aacb2b725', 'dressed', 'The guarantee was dressed up as a service agreement to evade disclosure.', '这项担保被包装成服务协议，以规避披露。'),
  ('27675a86-5622-4dcc-9a98-d90a9fb3f682-ex1', '27675a86-5622-4dcc-9a98-d90a9fb3f682', 'drought', 'The drought ruined the harvest.', '干旱毁了收成。'),
  ('27675a86-5622-4dcc-9a98-d90a9fb3f682-ex2', '27675a86-5622-4dcc-9a98-d90a9fb3f682', 'drought', 'Successive droughts compelled rationing of agricultural water allocations.', '连年干旱迫使农业用水配额实行定量分配。'),
  ('49be3de6-7fb1-447b-b719-ae035e5b06e7-ex1', '49be3de6-7fb1-447b-b719-ae035e5b06e7', 'regulator', 'The regulator approved the new medicine.', '监管机构批准了这种新药。'),
  ('49be3de6-7fb1-447b-b719-ae035e5b06e7-ex2', '49be3de6-7fb1-447b-b719-ae035e5b06e7', 'regulator', 'The regulator''s independence is the precondition of credible supervision.', '监管机构的独立性是可信监管的前提。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('fb3f7d8e-3eb5-441a-9ce8-03f379f8eccf-ex1', 'fb3f7d8e-3eb5-441a-9ce8-03f379f8eccf', 'dual', 'The device has a dual purpose.', '这个设备有双重用途。'),
  ('fb3f7d8e-3eb5-441a-9ce8-03f379f8eccf-ex2', 'fb3f7d8e-3eb5-441a-9ce8-03f379f8eccf', 'dual', 'Dual-class shares entrench founder control against shareholder challenge.', '双重股权结构巩固了创始人控制权，使股东难以挑战。'),
  ('7d0abfd0-6b6b-4973-a671-38c90c40cb86-ex1', '7d0abfd0-6b6b-4973-a671-38c90c40cb86', 'straw', 'He drank the juice through a straw.', '他用吸管喝果汁。'),
  ('7d0abfd0-6b6b-4973-a671-38c90c40cb86-ex2', '7d0abfd0-6b6b-4973-a671-38c90c40cb86', 'straw', 'The late disclosure was the final straw that exhausted regulatory patience.', '这次迟来的披露成了耗尽监管耐心的最后一根稻草。'),
  ('7e314be0-0f3c-488a-886b-3a251106ef40-ex1', '7e314be0-0f3c-488a-886b-3a251106ef40', 'dub', 'The film was dubbed into Chinese.', '这部电影被配成了中文。'),
  ('7e314be0-0f3c-488a-886b-3a251106ef40-ex2', '7e314be0-0f3c-488a-886b-3a251106ef40', 'dub', 'The press dubbed the provision a loophole before legislators conceded the point.', '在立法者承认这一点之前，媒体早已将该条款称为漏洞。'),
  ('6e1ed546-f9fb-403e-be4c-8aaf9eb82cc6-ex1', '6e1ed546-f9fb-403e-be4c-8aaf9eb82cc6', 'theological', 'He studies theological texts.', '他研究神学典籍。'),
  ('6e1ed546-f9fb-403e-be4c-8aaf9eb82cc6-ex2', '6e1ed546-f9fb-403e-be4c-8aaf9eb82cc6', 'theological', 'The dispute is almost theological: text against purpose in statutory construction.', '这场争论近乎神学之争：法规解释中文本与目的的对立。'),
  ('8ebef44e-2867-45cb-997d-1e7c986391da-ex1', '8ebef44e-2867-45cb-997d-1e7c986391da', 'dull', 'The lecture was long and dull.', '讲座又长又乏味。'),
  ('8ebef44e-2867-45cb-997d-1e7c986391da-ex2', '8ebef44e-2867-45cb-997d-1e7c986391da', 'dull', 'Prolonged stability dulled vigilance toward accumulating systemic risk.', '长期的稳定钝化了对系统性风险累积的警觉。'),
  ('54a99ef1-c96d-46c2-9116-4804a926d1df-ex1', '54a99ef1-c96d-46c2-9116-4804a926d1df', 'duo', 'The comedy duo made everyone laugh.', '这对喜剧搭档把大家逗笑了。'),
  ('54a99ef1-c96d-46c2-9116-4804a926d1df-ex2', '54a99ef1-c96d-46c2-9116-4804a926d1df', 'duo', 'The duo of leverage and opacity defines most modern financial crises.', '高杠杆与不透明这对组合是多数现代金融危机的共同特征。'),
  ('3a481b59-3ce8-4c14-a63a-24bf50d72fa2-ex1', '3a481b59-3ce8-4c14-a63a-24bf50d72fa2', 'exhaust', 'The car''s exhaust needs repair.', '汽车的排气管需要修理。'),
  ('3a481b59-3ce8-4c14-a63a-24bf50d72fa2-ex2', '3a481b59-3ce8-4c14-a63a-24bf50d72fa2', 'exhaust', 'Claimants must exhaust administrative remedies before seeking judicial review.', '索赔人必须先用尽行政救济，方可寻求司法审查。'),
  ('85204249-4828-458c-a1ef-4fef588baccb-ex1', '85204249-4828-458c-a1ef-4fef588baccb', 'duration', 'The duration of the movie is two hours.', '这部电影时长两小时。'),
  ('85204249-4828-458c-a1ef-4fef588baccb-ex2', '85204249-4828-458c-a1ef-4fef588baccb', 'duration', 'The measures remain in force for the duration of the declared emergency.', '这些措施在宣布的紧急状态期间持续有效。'),
  ('70905cc5-1565-4969-992d-e4359f155f01-ex1', '70905cc5-1565-4969-992d-e4359f155f01', 'dvd', 'We watched the movie on DVD.', '我们看了这部电影的DVD。'),
  ('70905cc5-1565-4969-992d-e4359f155f01-ex2', '70905cc5-1565-4969-992d-e4359f155f01', 'dvd', 'The evidence was preserved on DVDs sealed under the custody protocol.', '证据被刻录在按保管规程封存的DVD上。'),
  ('92a9ba61-0ddd-4bbd-9ecc-4c0b43d495ac-ex1', '92a9ba61-0ddd-4bbd-9ecc-4c0b43d495ac', 'globe', 'He spun the globe and pointed at random.', '他转动地球仪随手一指。'),
  ('92a9ba61-0ddd-4bbd-9ecc-4c0b43d495ac-ex2', '92a9ba61-0ddd-4bbd-9ecc-4c0b43d495ac', 'globe', 'Regulatory convergence proceeds unevenly across the globe.', '监管趋同在全球范围内进展并不均衡。'),
  ('3c2b56de-eb3e-4b6e-82c6-efc3836158c6-ex1', '3c2b56de-eb3e-4b6e-82c6-efc3836158c6', 'editorial', 'The paper''s editorial criticized the plan.', '报纸的社论批评了该计划。'),
  ('3c2b56de-eb3e-4b6e-82c6-efc3836158c6-ex2', '3c2b56de-eb3e-4b6e-82c6-efc3836158c6', 'editorial', 'The editorial independence of the broadcaster is statutorily protected.', '该广播机构的编辑独立性受法律保护。'),
  ('85838f81-19f8-4da7-b573-1adcc87075c7-ex1', '85838f81-19f8-4da7-b573-1adcc87075c7', 'fragile', 'Handle the vase carefully; it is fragile.', '小心搬这个花瓶，它易碎。'),
  ('85838f81-19f8-4da7-b573-1adcc87075c7-ex2', '85838f81-19f8-4da7-b573-1adcc87075c7', 'fragile', 'The recovery remains fragile and contingent on continued fiscal support.', '复苏依然脆弱，有赖于财政支持的延续。'),
  ('4b902054-0aad-4b23-a12e-8ddff15ee094-ex1', '4b902054-0aad-4b23-a12e-8ddff15ee094', 'educated', 'She is a well-educated young woman.', '她是一位受过良好教育的年轻女性。'),
  ('4b902054-0aad-4b23-a12e-8ddff15ee094-ex2', '4b902054-0aad-4b23-a12e-8ddff15ee094', 'educated', 'The disclosure must enable an educated assessment of the material risks.', '披露必须使人能够对重大风险作出有根据的评估。'),
  ('a3ba1027-0e44-48d1-bff7-14cc3e9273d8-ex1', 'a3ba1027-0e44-48d1-bff7-14cc3e9273d8', 'objection', 'Does anyone have an objection to the plan?', '有人对这个计划有异议吗？'),
