  ('a5cafad3-04fb-4edf-a0ec-bed69dbdcbaf-ex1', 'a5cafad3-04fb-4edf-a0ec-bed69dbdcbaf', 'email', 'Send me an email with the details.', '把详情用邮件发给我。'),
