  ('46b9c2cd-3ded-4c70-b616-73ca7d270a35-ex1', '46b9c2cd-3ded-4c70-b616-73ca7d270a35', 'cruel', 'Don''t be cruel to animals.', '不要虐待动物。'),
  ('46b9c2cd-3ded-4c70-b616-73ca7d270a35-ex2', '46b9c2cd-3ded-4c70-b616-73ca7d270a35', 'cruel', 'The clause prohibits punishment that is cruel or degrading.', '该条款禁止残忍或有辱人格的处罚。'),
  ('4846d0c8-afff-4903-99e7-74e97d29a67d-ex1', '4846d0c8-afff-4903-99e7-74e97d29a67d', 'entertain', 'He entertained the kids with magic tricks.', '他用魔术逗孩子们开心。'),
  ('4846d0c8-afff-4903-99e7-74e97d29a67d-ex2', '4846d0c8-afff-4903-99e7-74e97d29a67d', 'entertain', 'The court declined to entertain arguments raised for the first time on appeal.', '法院拒绝受理上诉时才首次提出的论点。'),
  ('178badda-a909-4fb9-891a-bd20a2d42a81-ex1', '178badda-a909-4fb9-891a-bd20a2d42a81', 'entertaining', 'The show was very entertaining.', '演出非常精彩有趣。'),
  ('178badda-a909-4fb9-891a-bd20a2d42a81-ex2', '178badda-a909-4fb9-891a-bd20a2d42a81', 'entertaining', 'Counsel''s submissions were entertaining yet doctrinally untenable.', '律师的陈词妙趣横生，在法理上却站不住脚。'),
  ('4d79ee0d-0b9e-49a5-a152-378d529d5428-ex1', '4d79ee0d-0b9e-49a5-a152-378d529d5428', 'mansion', 'The old mansion has twenty rooms.', '这座老宅有二十个房间。'),
  ('4d79ee0d-0b9e-49a5-a152-378d529d5428-ex2', '4d79ee0d-0b9e-49a5-a152-378d529d5428', 'mansion', 'The mansion was forfeited as proceeds of the documented fraud.', '这座豪宅作为经查证的欺诈所得被没收。'),
  ('c6ab165d-7df6-49a3-aed8-43bb763a8819-ex1', 'c6ab165d-7df6-49a3-aed8-43bb763a8819', 'enthusiast', 'He is a cycling enthusiast.', '他是骑行爱好者。'),
