  ('90ecdf03-e150-4cc5-aa3c-309bff933933-ex1', '90ecdf03-e150-4cc5-aa3c-309bff933933', 'authorize', 'I did not authorize this payment.', '我没有授权这笔付款。'),
  ('90ecdf03-e150-4cc5-aa3c-309bff933933-ex2', '90ecdf03-e150-4cc5-aa3c-309bff933933', 'authorize', 'Only the board may authorize transactions exceeding the chartered limits.', '只有董事会才能批准超出章程限额的交易。'),
  ('4a5b269b-4dc8-4126-ae54-0b5c19da33c7-ex1', '4a5b269b-4dc8-4126-ae54-0b5c19da33c7', 'cottage', 'They rented a cottage by the lake.', '他们在湖边租了一间小屋。'),
  ('4a5b269b-4dc8-4126-ae54-0b5c19da33c7-ex2', '4a5b269b-4dc8-4126-ae54-0b5c19da33c7', 'cottage', 'The cottage industry of compliance consulting boomed after the reforms.', '改革之后，合规咨询这一小型行业蓬勃兴起。'),
  ('6f72133f-88d9-4d74-a3f1-e040bbbe20dc-ex1', '6f72133f-88d9-4d74-a3f1-e040bbbe20dc', 'erupt', 'The volcano could erupt at any time.', '火山随时可能喷发。'),
  ('6f72133f-88d9-4d74-a3f1-e040bbbe20dc-ex2', '6f72133f-88d9-4d74-a3f1-e040bbbe20dc', 'erupt', 'Protests erupted once the subsidy cuts were formally announced.', '补贴削减一经正式宣布，抗议便随即爆发。'),
  ('ac46c0c8-6260-4277-a823-46017a6fccdf-ex1', 'ac46c0c8-6260-4277-a823-46017a6fccdf', 'driveway', 'Park the car in the driveway.', '把车停在车道上。'),
  ('ac46c0c8-6260-4277-a823-46017a6fccdf-ex2', 'ac46c0c8-6260-4277-a823-46017a6fccdf', 'driveway', 'The easement guarantees access across the neighbor''s driveway.', '地役权保障了穿越邻居车道的通行权。'),
  ('c17b2afe-8b4a-4cb3-a072-075177202d56-ex1', 'c17b2afe-8b4a-4cb3-a072-075177202d56', 'eternal', 'The stars seem eternal in the night sky.', '夜空中的星辰仿佛永恒。'),
  ('c17b2afe-8b4a-4cb3-a072-075177202d56-ex2', 'c17b2afe-8b4a-4cb3-a072-075177202d56', 'eternal', 'Vigilance is the eternal price of institutional integrity.', '警惕是维护机构诚信永恒的代价。'),
