  ('c1a965b1-32fc-47b7-bdf4-1f2ec5537884-ex1', 'c1a965b1-32fc-47b7-bdf4-1f2ec5537884', 'loyal', 'The dog is loyal to its owner.', '狗对主人很忠诚。'),
