  ('5eb7e16e-a3b9-4dbc-ac1d-507a6c1b7e48-ex1', '5eb7e16e-a3b9-4dbc-ac1d-507a6c1b7e48', 'disc', 'The music is stored on a disc.', '音乐存储在光盘上。'),
