  ('1aeabb8b-1b05-4083-9649-02d79ea5563e-ex2', '1aeabb8b-1b05-4083-9649-02d79ea5563e', 'disturbing', 'The audit paints a disturbing picture of normalized noncompliance.', '审计揭示了一幅违规常态化的令人不安的图景。'),
  ('d72589d4-c5cf-4cef-978c-00a5d99fa2de-ex1', 'd72589d4-c5cf-4cef-978c-00a5d99fa2de', 'fundamentally', 'The two plans are fundamentally different.', '这两个方案有着根本的不同。'),
  ('d72589d4-c5cf-4cef-978c-00a5d99fa2de-ex2', 'd72589d4-c5cf-4cef-978c-00a5d99fa2de', 'fundamentally', 'The ruling fundamentally reorders the allocation of evidentiary burdens.', '该裁决从根本上重构了举证责任的分配。'),
  ('717480b2-a791-4f73-9a7a-9dfbd825aa38-ex1', '717480b2-a791-4f73-9a7a-9dfbd825aa38', 'fundraising', 'The school held a fundraising event.', '学校举办了一场募捐活动。'),
  ('717480b2-a791-4f73-9a7a-9dfbd825aa38-ex2', '717480b2-a791-4f73-9a7a-9dfbd825aa38', 'fundraising', 'Political fundraising above the threshold triggers disclosure obligations.', '超过限额的政治筹款会触发披露义务。'),
  ('eb8d47b0-78d9-4c8e-87bf-1830c0c4fb88-ex1', 'eb8d47b0-78d9-4c8e-87bf-1830c0c4fb88', 'surveillance', 'The store has video surveillance.', '这家店装有视频监控。'),
  ('eb8d47b0-78d9-4c8e-87bf-1830c0c4fb88-ex2', 'eb8d47b0-78d9-4c8e-87bf-1830c0c4fb88', 'surveillance', 'Mass surveillance absent individualized warrant violates the charter.', '未经个案令状的大规模监控违反宪章。'),
  ('8e7460af-44de-420d-94ba-f3f386616de1-ex1', '8e7460af-44de-420d-94ba-f3f386616de1', 'furious', 'She was furious about the broken vase.', '花瓶被打碎让她大为光火。'),
  ('8e7460af-44de-420d-94ba-f3f386616de1-ex2', '8e7460af-44de-420d-94ba-f3f386616de1', 'furious', 'Furious creditors demanded the immediate removal of the trustee.', '愤怒的债权人要求立即撤换受托人。'),
  ('c6d4e35c-43ff-422a-87fc-21c1f01c79e3-ex1', 'c6d4e35c-43ff-422a-87fc-21c1f01c79e3', 'magnetic', 'The fridge has magnetic stickers.', '冰箱上贴着磁性贴。'),
  ('c6d4e35c-43ff-422a-87fc-21c1f01c79e3-ex2', 'c6d4e35c-43ff-422a-87fc-21c1f01c79e3', 'magnetic', 'The magnetic resonance data corroborated the claimed injury.', '磁共振数据印证了所主张的伤情。'),
  ('1df02f88-e7ac-40eb-bfef-9bd00dd74d0a-ex1', '1df02f88-e7ac-40eb-bfef-9bd00dd74d0a', 'technician', 'The technician fixed the printer.', '技术员修好了打印机。'),
  ('1df02f88-e7ac-40eb-bfef-9bd00dd74d0a-ex2', '1df02f88-e7ac-40eb-bfef-9bd00dd74d0a', 'technician', 'Only certified technicians may service the regulated equipment.', '只有持证技术人员才能维护受管制设备。'),
  ('78a9767b-4743-41e5-a6e6-f0ca439f1264-ex1', '78a9767b-4743-41e5-a6e6-f0ca439f1264', 'further', 'Do you have any further questions?', '你还有其他问题吗？'),
  ('78a9767b-4743-41e5-a6e6-f0ca439f1264-ex2', '78a9767b-4743-41e5-a6e6-f0ca439f1264', 'further', 'The tribunal ordered further disclosure before hearing the merits.', '法庭在实体审理之前下令进一步披露。'),
  ('288a54af-6a15-4986-beb0-504b5c829ddf-ex1', '288a54af-6a15-4986-beb0-504b5c829ddf', 'mutter', 'He muttered something under his breath.', '他低声嘀咕了几句。'),
  ('288a54af-6a15-4986-beb0-504b5c829ddf-ex2', '288a54af-6a15-4986-beb0-504b5c829ddf', 'mutter', 'Markets muttered doubts long before the formal downgrade arrived.', '早在正式降级之前，市场就已暗流涌动、疑虑四起。'),
  ('9a1a3055-87dd-4dd0-b4dc-87894075b728-ex1', '9a1a3055-87dd-4dd0-b4dc-87894075b728', 'gallon', 'The tank holds fifty gallons.', '这个水箱能装五十加仑。'),
  ('9a1a3055-87dd-4dd0-b4dc-87894075b728-ex2', '9a1a3055-87dd-4dd0-b4dc-87894075b728', 'gallon', 'Fuel taxes are levied per gallon at rates the statute indexes to inflation.', '燃油税按加仑征收，税率依法规与通胀挂钩。'),
  ('b4da9cd3-cc75-43ae-a41e-368b67309c84-ex1', 'b4da9cd3-cc75-43ae-a41e-368b67309c84', 'devastating', 'The drought had a devastating effect.', '干旱造成了毁灭性影响。'),
  ('b4da9cd3-cc75-43ae-a41e-368b67309c84-ex2', 'b4da9cd3-cc75-43ae-a41e-368b67309c84', 'devastating', 'The restatement had a devastating effect on the issuer''s credit standing.', '财报重述对发行人的信用状况造成了毁灭性打击。'),
  ('e6015bfc-1a36-4d2a-b65c-5a4afe1db487-ex1', 'e6015bfc-1a36-4d2a-b65c-5a4afe1db487', 'gambling', 'Gambling is illegal in many places.', '赌博在许多地方是非法的。'),
  ('e6015bfc-1a36-4d2a-b65c-5a4afe1db487-ex2', 'e6015bfc-1a36-4d2a-b65c-5a4afe1db487', 'gambling', 'Online gambling operators face licensing duties across jurisdictions.', '网络博彩运营商在各司法管辖区都面临牌照义务。'),
  ('230ba941-0a85-493a-97f7-2468662886d6-ex1', '230ba941-0a85-493a-97f7-2468662886d6', 'depart', 'The train departs at noon.', '火车中午发车。'),
  ('230ba941-0a85-493a-97f7-2468662886d6-ex2', '230ba941-0a85-493a-97f7-2468662886d6', 'depart', 'The court declined to depart from the precedent absent compelling reason.', '如无充分理由，法院拒绝背离先例。'),
  ('24aab122-ce4c-4e6e-bc7f-b411b3c8f3fa-ex1', '24aab122-ce4c-4e6e-bc7f-b411b3c8f3fa', 'gaming', 'He spends weekends gaming with friends.', '他周末和朋友打游戏。'),
  ('24aab122-ce4c-4e6e-bc7f-b411b3c8f3fa-ex2', '24aab122-ce4c-4e6e-bc7f-b411b3c8f3fa', 'gaming', 'The rules target gaming of the thresholds through transaction splitting.', '这些规则针对通过拆分交易钻门槛空子的行为。'),
  ('0065c59c-f3d2-41d7-abb4-7a4b3e84c185-ex1', '0065c59c-f3d2-41d7-abb4-7a4b3e84c185', 'generic', 'The store sells generic medicines.', '这家店出售非专利药。'),
  ('0065c59c-f3d2-41d7-abb4-7a4b3e84c185-ex2', '0065c59c-f3d2-41d7-abb4-7a4b3e84c185', 'generic', 'Generic entry collapsed prices once the patent expired.', '专利到期后，仿制药的进入使价格应声暴跌。'),
  ('4281808b-4040-4d45-afdd-f52388c1b3bf-ex1', '4281808b-4040-4d45-afdd-f52388c1b3bf', 'arrow', 'Follow the arrows to the exit.', '沿着箭头指示走到出口。'),
  ('4281808b-4040-4d45-afdd-f52388c1b3bf-ex2', '4281808b-4040-4d45-afdd-f52388c1b3bf', 'arrow', 'The indicators all point in one arrow-straight direction: deterioration.', '所有指标都笔直地指向同一个方向：恶化。'),
  ('481c5382-4a82-4ecf-bac7-1747f2ffded7-ex1', '481c5382-4a82-4ecf-bac7-1747f2ffded7', 'genocide', 'The museum remembers the victims of genocide.', '博物馆纪念种族灭绝的受害者。'),
  ('481c5382-4a82-4ecf-bac7-1747f2ffded7-ex2', '481c5382-4a82-4ecf-bac7-1747f2ffded7', 'genocide', 'The convention obliges states to prevent and punish genocide.', '该公约要求各国预防并惩治种族灭绝罪。'),
  ('b836bb35-4016-497e-944c-ba9cf5c4fb61-ex1', 'b836bb35-4016-497e-944c-ba9cf5c4fb61', 'trauma', 'The accident left lasting trauma.', '事故留下了持久的创伤。'),
  ('b836bb35-4016-497e-944c-ba9cf5c4fb61-ex2', 'b836bb35-4016-497e-944c-ba9cf5c4fb61', 'trauma', 'Compensation extends to psychological trauma where causation is established.', '在因果关系成立时，赔偿范围延及心理创伤。'),
  ('9df962e6-4311-4e84-b96b-bd042eb09b82-ex1', '9df962e6-4311-4e84-b96b-bd042eb09b82', 'genuinely', 'She was genuinely happy for us.', '她由衷地为我们高兴。'),
  ('9df962e6-4311-4e84-b96b-bd042eb09b82-ex2', '9df962e6-4311-4e84-b96b-bd042eb09b82', 'genuinely', 'The tribunal must determine whether the dispute is genuinely commercial.', '法庭必须认定该争议是否确属商事性质。'),
  ('ec96d3e7-a415-4658-8c5b-c041e3408d1d-ex1', 'ec96d3e7-a415-4658-8c5b-c041e3408d1d', 'neighboring', 'We visited the neighboring village.', '我们去了邻村。'),
  ('ec96d3e7-a415-4658-8c5b-c041e3408d1d-ex2', 'ec96d3e7-a415-4658-8c5b-c041e3408d1d', 'neighboring', 'The doctrine obliges states to prevent harm to neighboring territories.', '该原则要求各国防止对邻国领土造成损害。'),
  ('22dc4e26-8d91-4815-97f1-894561011476-ex1', '22dc4e26-8d91-4815-97f1-894561011476', 'soak', 'Soak the beans overnight.', '把豆子泡一夜。'),
  ('22dc4e26-8d91-4815-97f1-894561011476-ex2', '22dc4e26-8d91-4815-97f1-894561011476', 'soak', 'The senior tranche was structured to soak up first losses.', '优先层级的结构设计旨在吸收首批损失。'),
  ('7997e0f1-3326-4c85-9882-b81f1bd9ea04-ex1', '7997e0f1-3326-4c85-9882-b81f1bd9ea04', 'geography', 'Geography is her favorite subject.', '地理是她最喜欢的科目。'),
  ('7997e0f1-3326-4c85-9882-b81f1bd9ea04-ex2', '7997e0f1-3326-4c85-9882-b81f1bd9ea04', 'geography', 'The geography of enforcement maps closely onto supervisory funding.', '执法力度的地域分布与监管经费的分布高度吻合。'),
  ('35b620b9-6edb-40df-9b3a-6dad197be97f-ex1', '35b620b9-6edb-40df-9b3a-6dad197be97f', 'gig', 'The band has a gig this weekend.', '乐队这周末有演出。'),
  ('35b620b9-6edb-40df-9b3a-6dad197be97f-ex2', '35b620b9-6edb-40df-9b3a-6dad197be97f', 'gig', 'The statute extends employment protections to gig economy workers.', '该法规将就业保护扩展至零工经济从业者。'),
  ('ef67cf1b-cbc6-44b4-bae0-3901a3b63550-ex1', 'ef67cf1b-cbc6-44b4-bae0-3901a3b63550', 'ribbon', 'She tied the gift with a red ribbon.', '她用红丝带系好礼物。'),
  ('ef67cf1b-cbc6-44b4-bae0-3901a3b63550-ex2', 'ef67cf1b-cbc6-44b4-bae0-3901a3b63550', 'ribbon', 'The ceremony''s ribbon-cutting masked unresolved disputes over financing.', '剪彩仪式掩盖了融资方面尚未解决的争议。'),
  ('2b848c61-83f8-41cf-8528-687794557a12-ex1', '2b848c61-83f8-41cf-8528-687794557a12', 'meantime', 'In the meantime, let''s prepare dinner.', '在此期间，我们先准备晚饭吧。'),
  ('2b848c61-83f8-41cf-8528-687794557a12-ex2', '2b848c61-83f8-41cf-8528-687794557a12', 'meantime', 'In the meantime, the interim measures remain fully enforceable.', '在此期间，临时措施仍具有完全的执行力。')
INSERT INTO vocab_examples (id, vocabulary_id, word, sentence_en, sentence_zh) VALUES
  ('c1a7435a-cbba-4a03-a2e5-923ffe6171df-ex1', 'c1a7435a-cbba-4a03-a2e5-923ffe6171df', 'globalization', 'Globalization connects distant markets.', '全球化将遥远的市场连接起来。'),
  ('c1a7435a-cbba-4a03-a2e5-923ffe6171df-ex2', 'c1a7435a-cbba-4a03-a2e5-923ffe6171df', 'globalization', 'Globalization outpaced the governance frameworks meant to channel it.', '全球化的速度超过了本应引导它的治理框架。'),
  ('0e12aafd-0407-426b-8d59-8f3428115707-ex1', '0e12aafd-0407-426b-8d59-8f3428115707', 'transmit', 'Mosquitoes can transmit disease.', '蚊子会传播疾病。'),
  ('0e12aafd-0407-426b-8d59-8f3428115707-ex2', '0e12aafd-0407-426b-8d59-8f3428115707', 'transmit', 'The duty to transmit records survives the dissolution of the entity.', '移交记录的义务在实体解散后继续存在。'),
  ('e50f9363-9c32-4c65-b92d-f36393398b7b-ex1', 'e50f9363-9c32-4c65-b92d-f36393398b7b', 'glorious', 'It was a glorious summer day.', '那是一个阳光灿烂的夏日。'),
  ('e50f9363-9c32-4c65-b92d-f36393398b7b-ex2', 'e50f9363-9c32-4c65-b92d-f36393398b7b', 'glorious', 'The glorious rhetoric of the charter contrasts with its weak enforcement.', '宪章辞藻的华美与其执行的乏力形成鲜明对照。'),
  ('f4752177-e4f6-4a5b-b61f-e8064511ee7e-ex1', 'f4752177-e4f6-4a5b-b61f-e8064511ee7e', 'goodbye', 'We said goodbye at the station.', '我们在车站道了别。'),
  ('f4752177-e4f6-4a5b-b61f-e8064511ee7e-ex2', 'f4752177-e4f6-4a5b-b61f-e8064511ee7e', 'goodbye', 'The reform bid goodbye to exemptions incumbents had exploited for decades.', '这项改革告别了在位者利用数十年的豁免条款。'),
  ('963bf2ba-13d2-448e-8447-aac85fe30613-ex1', '963bf2ba-13d2-448e-8447-aac85fe30613', 'harvest', 'The harvest was good this year.', '今年收成很好。'),
  ('963bf2ba-13d2-448e-8447-aac85fe30613-ex2', '963bf2ba-13d2-448e-8447-aac85fe30613', 'harvest', 'Successive failed harvests compounded the region''s food insecurity.', '连年歉收加剧了该地区的粮食不安全。'),
  ('cbfdf03d-4605-4c68-9bca-29bd664510d3-ex1', 'cbfdf03d-4605-4c68-9bca-29bd664510d3', 'goodness', 'Thank goodness you are safe!', '谢天谢地你平安无事！'),
  ('cbfdf03d-4605-4c68-9bca-29bd664510d3-ex2', 'cbfdf03d-4605-4c68-9bca-29bd664510d3', 'goodness', 'The settlement rested on documented obligations, not presumed goodness.', '和解建立在书面义务之上，而非对善意的推定。'),
  ('5e7d8bc1-2916-4ccf-ae35-cc229df15e12-ex1', '5e7d8bc1-2916-4ccf-ae35-cc229df15e12', 'consecutive', 'It rained for five consecutive days.', '连续下了五天雨。'),
  ('5e7d8bc1-2916-4ccf-ae35-cc229df15e12-ex2', '5e7d8bc1-2916-4ccf-ae35-cc229df15e12', 'consecutive', 'Revenue declined for the third consecutive quarter despite cost cuts.', '尽管削减了成本，营收仍连续第三个季度下滑。'),
  ('c1c4ca70-c0aa-4669-870f-efa2207d1230-ex1', 'c1c4ca70-c0aa-4669-870f-efa2207d1230', 'goods', 'The store sells household goods.', '这家店出售家居用品。'),
  ('c1c4ca70-c0aa-4669-870f-efa2207d1230-ex2', 'c1c4ca70-c0aa-4669-870f-efa2207d1230', 'goods', 'The convention governs international carriage of goods by sea.', '该公约规范国际海上货物运输。'),
  ('c46c333a-aacb-4ded-acf1-9118e882eae8-ex1', 'c46c333a-aacb-4ded-acf1-9118e882eae8', 'gorgeous', 'The sunset was absolutely gorgeous.', '日落美极了。'),
  ('c46c333a-aacb-4ded-acf1-9118e882eae8-ex2', 'c46c333a-aacb-4ded-acf1-9118e882eae8', 'gorgeous', 'The gorgeous prospectus prose obscured thoroughly inconvenient liabilities.', '招股书华丽的文笔掩盖了极为棘手的负债。'),
  ('90a06d56-63d3-443d-a74c-bbea90ccc7f7-ex1', '90a06d56-63d3-443d-a74c-bbea90ccc7f7', 'governance', 'Good governance builds public trust.', '良好的治理建立公众信任。'),
  ('90a06d56-63d3-443d-a74c-bbea90ccc7f7-ex2', '90a06d56-63d3-443d-a74c-bbea90ccc7f7', 'governance', 'The inquiry attributed the collapse to failures of governance, not markets.', '调查将这次崩溃归因于治理失灵，而非市场失灵。'),
  ('f9bbc27c-fc43-43a2-8ecc-e0a7784746ea-ex1', 'f9bbc27c-fc43-43a2-8ecc-e0a7784746ea', 'coordinate', 'Let''s coordinate our schedules.', '我们协调一下日程吧。'),
  ('f9bbc27c-fc43-43a2-8ecc-e0a7784746ea-ex2', 'f9bbc27c-fc43-43a2-8ecc-e0a7784746ea', 'coordinate', 'The authorities coordinate enforcement through a joint secretariat.', '各主管机构通过联合秘书处协调执法。'),
  ('d92f32ff-927d-4407-b158-1b62dcb36b54-ex1', 'd92f32ff-927d-4407-b158-1b62dcb36b54', 'graphic', 'The book has graphic illustrations.', '这本书配有生动的插图。'),
  ('d92f32ff-927d-4407-b158-1b62dcb36b54-ex2', 'd92f32ff-927d-4407-b158-1b62dcb36b54', 'graphic', 'The testimony offered a graphic account of the conditions in detention.', '证词生动地描述了羁押期间的状况。'),
  ('503e3f38-926f-45bb-9431-acb0891854f3-ex1', '503e3f38-926f-45bb-9431-acb0891854f3', 'graphics', 'The game has amazing graphics.', '这款游戏画面惊艳。'),
  ('503e3f38-926f-45bb-9431-acb0891854f3-ex2', '503e3f38-926f-45bb-9431-acb0891854f3', 'graphics', 'The misleading graphics in the prospectus understated the leverage ratio.', '招股书中误导性的图表低估了杠杆比率。'),
  ('128c6c6e-37d7-4a7a-bc90-7f2a651a51d1-ex1', '128c6c6e-37d7-4a7a-bc90-7f2a651a51d1', 'greenhouse', 'Tomatoes grow well in the greenhouse.', '番茄在温室里长势良好。'),
  ('128c6c6e-37d7-4a7a-bc90-7f2a651a51d1-ex2', '128c6c6e-37d7-4a7a-bc90-7f2a651a51d1', 'greenhouse', 'The levy targets greenhouse gas emissions verified by independent audit.', '该税项针对经独立审计核证的温室气体排放。'),
  ('bdb39fe8-ee5b-428d-b958-c6b0117680aa-ex1', 'bdb39fe8-ee5b-428d-b958-c6b0117680aa', 'spy', 'The kids played spy games in the yard.', '孩子们在院子里玩间谍游戏。'),
  ('bdb39fe8-ee5b-428d-b958-c6b0117680aa-ex2', 'bdb39fe8-ee5b-428d-b958-c6b0117680aa', 'spy', 'The defendant was convicted of conspiring to spy for a foreign power.', '被告因共谋为外国势力从事间谍活动而被定罪。'),
  ('609ff729-69e5-40ab-9558-14643602dc50-ex1', '609ff729-69e5-40ab-9558-14643602dc50', 'slot', 'Put the coin in the slot.', '把硬币投进投币口。'),
  ('609ff729-69e5-40ab-9558-14643602dc50-ex2', '609ff729-69e5-40ab-9558-14643602dc50', 'slot', 'Airport slots were reallocated as a condition of merger clearance.', '机场起降时刻的重新分配是合并获批的条件。'),
  ('80e400dc-890c-4ff8-9944-3a2aa84b313e-ex1', '80e400dc-890c-4ff8-9944-3a2aa84b313e', 'grid', 'Draw a grid on the paper.', '在纸上画一个网格。'),
  ('80e400dc-890c-4ff8-9944-3a2aa84b313e-ex2', '80e400dc-890c-4ff8-9944-3a2aa84b313e', 'grid', 'The grid operator bears statutory responsibility for supply security.', '电网运营商对供电安全负有法定责任。'),
  ('5e2e26cb-9928-4e38-9edd-741ad64ca915-ex1', '5e2e26cb-9928-4e38-9edd-741ad64ca915', 'riot', 'The riot lasted through the night.', '骚乱持续了一整夜。'),
